INSERT INTO `books` (`id`, `name`, `description`, `price`, `parent_id`, `parent_level`, `teach_time`) VALUES
(1, 'Геолог', 'Позволяет изготавливать геологические приборы. Необходим 3 уровень Геологии, для изучения Шахтерства', 0, NULL, NULL, 60),
(2, 'Шахтер', 'Сокращает время добычи ресурсов на 5%25 за каждый уровень. Необходим Шахтер 3 уровень для изучения Металлургии.', 0, 1, 3, 900),
(3, 'Металлург', 'Сокращает время переплавки ископаемых и различных объектов на 5%25 за каждый уровень. Необходим 3 уровень Металургии для изучения Производственника', 0, 2, 3, 120),
(4, 'Скорочтение', 'Сокращает время изучения других наук на 5%25 за каждый уровень.', 0, NULL, NULL, 240),
(5, 'Строитель', 'Сокращает время постройки объектов на 5%25 за каждый уровень. Необходим 3 уровень для изучения технолога.', 0, NULL, NULL, 120),
(6, 'Производственник', 'Сокращает время производства различных деталей на 5%25 за каждый уровень. Необходим третий уровень для изучения Инженера', 0, 3, 3, 240),
(7, 'Инженер', 'Увеличивает вероятность создания чертежа по образцу на 8%25 за каждый уровень. Необходим 5 уровень для изучения навигации. Необходим 8 уровень для изучения тактики и стратегии.', 0, 6, 3, 800),
(8, 'Навигатор', 'Сокращает время перелета между двумя точками пространства на 2.5%25 за каждый уровень. Необходим 3 уровень для изучения "Гипернавигации" и 5 уровень для изучения науки "Бомбардир"', 0, 7, 5, 1200),
(9, 'Гипернавигатор', 'Сокращает время перелета в гиперпространстве на 2.5%25 за каждый уровень.', 0, 8, 3, 2400),
(10, 'Бомбардир', 'Увеличивает точность попадания при атаке планеты. Чем выше уровень, тем больше вероятность, что пострадают только военные постройки. при 0 уровне ведется "ковровая бомбардировка" до уничтожения всех военных сооружений. При 10 уровне уничтожаются только военные сооружения точечным бомбометанием. Требуется 5 уровень для изучения Абордажа.', 0, 8, 5, 1200),
(11, 'Абордаж', 'Увеличивает вероятность абордажа. Изначально вероятность захвата корабля в бою 0%25 с каждым новым уровнем вероятность увеличивается на 2%25. Максимум 20%25. При захвате корабля он выводится с поля боя и передается в собственность противника со всем содержимым. Если ваш статус меньше 0 (вы относитесь к космическим пиратам) вероятность увеличивается пропорционально статусу (0 -10) 5%25, (-10 -100) 15%25, (-100 -1000) 30%25, (-1000 -10000) 40%25, (меньше -10000) 50%25.', 1, 10, 5, 3200),
(12, 'Тактик', 'Определяет очередность кораблей с которых производится залп. Чем выше уровень тем более математически правильная последовательность выбирается во время атаки.', 0, 7, 8, 2400),
(13, 'Стратег', 'Определяет очередность кораблей и построек по которым ведется огонь. Чем выше уровень тем более математически правильные объекты выбираются для атаки.', 0, 7, 8, 3200),
(14, 'Снайпер', 'Позволяет реже промахиваться в космическом бою. Изначально точное попадание в 60%25 выстрелов с каждым уровнем показатель увеличивается на 2%25. Максимальная точность попаданий 80%25. В случае промаха выстрел не наносит повреждений.', 0, 7, 5, 1200),
(15, 'Технолог', 'Увеличивает время и количество добычи любого минерала на 10%25 на каждый уровень. Необходим 10 уровень для изучения профильных технологов.', 0, 5, 3, 480),
(16, 'Технолог карьеров', 'Увеличивает время и количество добычи минералов с верхнего слоя на 10%25 за каждый уровень.', 1, 15, 10, 720),
(17, 'Технолог шахт', 'Увеличивает время и количество добычи минералов со среднего слоя на 10%25 за каждый уровень.', 1, 15, 10, 720),
(18, 'Технолог буровых', 'Увеличивает время и количество добычи минералов с глубинного слоя на 10%25 за каждый уровень.', 1, 15, 10, 720),
(19, 'Технолог орбитальных заводов', 'Увеличивает время и количество добычи газа на орбитальных газодобывающих заводах на 10%25 за каждый уровень.', 1, 15, 10, 720),
(20, 'Защита планет', 'Увеличивает устойчивость планетарных щитов на 25%25 за каждый уровень.', 0, 4, 10, 320),
(21, 'Плазменная оборона', 'Увеличивает силу оборонительных плазменных установок на 100%25 за каждый уровень.', 0, 20, 5, 600),
(22, 'Лазерная оборона', 'Увеличивает силу оборонительных лазерных установок на 100%25 за каждый уровень.', 0, 20, 5, 600),
(23, 'Мазерная оборона', 'Увеличивает силу планетарных оборонительных мазеров на 25%25 за каждый уровень.', 0, 20, 7, 600),
(24, 'Квантовая оборона', 'Увеличивает силу орбитальных квантовых установок на 25%25 за каждый уровень.', 0, 20, 7, 600),
(25, 'Физик ядерщик', 'Ускоряет процесс переработки материалов на термоядерном преобразователе каждый уровень дает 4%25 ускорения. Требует больших знаний в геологии.', 0, 1, 10, 720),
(26, 'Астроинженер', 'Уменьшает время перемещения планет на 5%25 за уровень при использовании корабля "гипер врата".', 1, 7, 10, 800);
