(5054, '<b>Уваровит</b> <u><a href=''page.php?id=2%26ml=5054''>Показать на карте</a></u>\nПриродный минерал <font color=''#00FFFF''>третьей</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Кислород O''>Кислород O</a></u>				38\n<u><a href=''page.php?id=6%26itm=Кальций Ca''>Кальций Ca</a></u>				24\n<u><a href=''page.php?id=6%26itm=Хром Cr''>Хром Cr</a></u>					21\n<u><a href=''page.php?id=6%26itm=Кремний Si''>Кремний Si</a></u>				16');
INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(5055, '<b>Флюорит</b> <u><a href=''page.php?id=2%26ml=5055''>Показать на карте</a></u>\nПриродный минерал <font color=''#00FFFF''>второй</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Кальций Ca''>Кальций Ca</a></u>				51\n<u><a href=''page.php?id=6%26itm=Фтор F''>Фтор F</a></u>					48'),
(5056, '<b>Циркон</b> <u><a href=''page.php?id=2%26ml=5056''>Показать на карте</a></u>\nПриродный минерал <font color=''#00FFFF''>третьей</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Цирконий Zr''>Цирконий Zr</a></u>				49\n<u><a href=''page.php?id=6%26itm=Кислород O''>Кислород O</a></u>				35\n<u><a href=''page.php?id=6%26itm=Кремний Si''>Кремний Si</a></u>				15'),
(5057, '<b>Шеелит</b> <u><a href=''page.php?id=2%26ml=5057''>Показать на карте</a></u>\nПриродный минерал <font color=''#00FFFF''>третьей</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Вольфрам W''>Вольфрам W</a></u>				63\n<u><a href=''page.php?id=6%26itm=Кислород O''>Кислород O</a></u>				22\n<u><a href=''page.php?id=6%26itm=Кальций Ca''>Кальций Ca</a></u>				14'),
(5058, '<b>Эвдиалит</b> <u><a href=''page.php?id=2%26ml=5058''>Показать на карте</a></u>\nПриродный минерал <font color=''#00FFFF''>третьей</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Кислород O''>Кислород O</a></u>				38\n<u><a href=''page.php?id=6%26itm=Кремний Si''>Кремний Si</a></u>				22\n<u><a href=''page.php?id=6%26itm=Цирконий Zr''>Цирконий Zr</a></u>				9\n<u><a href=''page.php?id=6%26itm=Натрий Na''>Натрий Na</a></u>					9\n<u><a href=''page.php?id=6%26itm=Цезий Cs''>Цезий Cs</a></u>					7\n<u><a href=''page.php?id=6%26itm=Кальций Ca''>Кальций Ca</a></u>				6\n<u><a href=''page.php?id=6%26itm=Железо Fe''>Железо Fe</a></u>				3\n<u><a href=''page.php?id=6%26itm=Марганец Mn''>Марганец Mn</a></u>				2\n<u><a href=''page.php?id=6%26itm=Водород H''>Водород H</a></u>				1\n<u><a href=''page.php?id=6%26itm=Иттрий Y''>Иттрий Y</a></u>					1\n<u><a href=''page.php?id=6%26itm=Хлор Cl''>Хлор Cl</a></u>					1'),
(5059, '<b>Эритрин</b> <u><a href=''page.php?id=2%26ml=5059''>Показать на карте</a></u>\nПриродный минерал <font color=''#00FFFF''>третьей</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Кислород O''>Кислород O</a></u>				43\n<u><a href=''page.php?id=6%26itm=Кобальт Co''>Кобальт Co</a></u>				29\n<u><a href=''page.php?id=6%26itm=Мышьяк As''>Мышьяк As</a></u>				25\n<u><a href=''page.php?id=6%26itm=Водород H''>Водород H</a></u>				2'),
(5060, '<img src="img/9.png"><b>Ярозит</b>\nПриродный минерал <font color=''#00FFFF''>первой</font> группы.\n\nСодержит полезные ископаемые:\n<u><a href=''page.php?id=6%26itm=Кислород O''>Кислород O</a></u>				44\n<u><a href=''page.php?id=6%26itm=Железо Fe''>Железо Fe</a></u>				33\n<u><a href=''page.php?id=6%26itm=Сера S''>Сера S</a></u>					13\n<u><a href=''page.php?id=6%26itm=Калий K''>Калий K</a></u>					8\n<u><a href=''page.php?id=6%26itm=Водород H''>Водород H</a></u>				1'),
(6000, '<b>Геологический зонд</b>\n\nИспользуется для проведения разведки планеты. Ресурсоемкость зонда очень мала, что позволяет изготавливать его еще на первом этапе колонизации. Чертеж зонда изначально передается колонизатору.\nПри наличии зонда появляется возможность "усовершенствовать" любую не занятую точку на планете. При первом запуске зонд углубится до среднего слоя и проведет анализ породы. Используя второй зонд в той же точке, исследуется глубинный слой планеты. Зонды являются одноразовыми устройствами и теряются в породе навсегда, поэтому для каждого исследования необходим новый зонд.'),
(6001, '<b>Корпус шатла</b>\n\nКорпус представляет собой поверхность шатла собранную из отдельных пластин. Основной материал корпуса это титан, как правило, по внешнему виду легко отличить разный тип кораблей, однако существуют корабли с нестандартным наполнением.'),
(6002, '<b>Малый ядерный реактор</b>\n\nПо сути своей одноразовый реактор. Топливо для реактора загружается один раз на заводе во время изготовления и в последующем не заменяется. Теоретически считается, что топлива хватит для нормальной работы в течении 35 лет. В настоящее время нет ядерных реакторов с таким сроком службы, поэтому практически срок службы реактора пока не подтвержден.\n\nДорабатывается до Среднего ядерного реактора\n\nМощность реактора: 30 ГВт'),
(6003, '<b>Антигравитационный двигатель</b>\n\nИспользуется на кораблях планетарного базирования, не потребляет топливо и позволяет очень быстро выводить корабль на орбиту. Не приемлемо использование в космическом пространстве ввиду отсутствия достаточных источников гравитационного поля. Двигатель не позволяет перемещаться в космосе. Двигатель ограничен в грузоподъемности ввиду особенности работы, для поднятия большой массы не предназначен, из-за этой конструктивной особенности не устанавливается на больших кораблях. Однако существует ряд малых кораблей на которых устанавливаются двигатели 2-х и более типов одновременно, что делает такие корабли незаменимыми разведчиками.\n\nМощность двигателя 200 МВт'),
(6004, '<b>Малый грузовой отсек</b>\n\nОсновная деталь малых кораблей. Разработан как легкий и достаточно прочный отсек для хранения любых материалов. Иногда малый грузовой отсек используется в качестве буферного накопителя на крупных кораблях.\n\nДорабатывается до Большого грузового отсека\n\nВместимость отсека: 850'),
(6005, '<b>Кабина шатла</b>\n\nКабина это основное место пребывания пилота во время перемещения. В кабине установлена вся аппаратура для управления кораблем. Кабина шатла как правило не очень комфортна, поскольку этот тип кораблей не создан для длительных перемещений.'),
(6006, '<b>Корпус среднего шатла</b>\n\nКорпус среднего шатла представляет собой доработанный корпус малого шатла. Защищенность и прочность корпуса остались на прежнем уровне.'),
(6007, '<b>Корпус большого шатла</b>\n\nКорпус в основном состоит с прочных и легких сплавов и рассчитан на многократные перегрузки при взлете и посадке, даже при полной загрузке шатла. Большой шатл как и все шатлы представляет собой корабль с внешним каркасом, поэтому корпус является самой прочной частью всего корабля.'),
(6008, '<b>Средний ядерный реактор</b>\n\nРеактор получает энергию от деления ядер. Как и в малом реакторе, основным элементом деления является дейтерий. Количество загруженного топлива достаточно на несколько сотен лет работы и в настоящее время реакторы считаются одноразовыми, однако, пока не зарегистрирована замена реактора из-за малого количества топлива.\n\nРазрабатывается из малого ядерного реактора\n\nМощность реактора: 60 ГВт'),
(6009, '<b>Малый термоядерный реактор</b>\n\nРеактор производит большое количество энергии сравнимое со средним ядерным реактором, однако возможность быстро наращивать мощность позволяет использовать данный тип реакторов на военных кораблях. Структурно реактор представляет собой диффузионную камеру и итератор перегретой плазмы. После реакции термоядерного синтеза продуктом реакции являются нестабильные изотопы He3 и He4, которые со временем превращается в различные изотопы водорода и повторно используется в синтезе. Загрузка реактора топливом производится один раз во время изготовления, далее реактор способен проработать несколько тысяч лет (точный срок службы пока экспериментально не доказан)\n\nДорабатывается до Среднего термоядерного реактора\n\nМощность реактора: 75 ГВт'),
(6010, '<b>Большой грузовой отсек</b>\n\nБольшой грузовой отсек устанавливается на большие транспортные и некоторые военные корабли. Отсек представляет собой пустую капсулу с возможностью установки кронштейнов и креплений. В некоторых нестандартных кораблях отсек используется как оружейная комната.\n\nРазрабатывается из Грузового отсека\n\nДорабатывается до Бомбового отсека\n\nВместимость отсека: 10000'),
(6011, '<b>Диффузный двигатель</b>\n\nНа заре космонавтики использовались реактивные двигатели, позже начали использовать ионные двигатели. Но у обоих типов двигателей были недостатки: реактивные двигатели требовали большого количества топлива, ионные двигатели давали очень малую тягу. Симбиозом этих двух двигателей стал диффузный двигатель. Принцип его действия основан на ионизации водорода с последующим раздельным ускорением протонов и электронов. За счет околосветовых скоростей истекания топлива двигатели обладают внушительной тягой. Топливом в данном случае служит водород, который легко добывается из верхних слоев атмосферы газовых гигантов.\n\nДорабатывается до Ионного двигателя'),
(7001, '<b>Малый шатл</b>\n\nСамый простой корабль, собрать который можно используя лишь ресурсы поверхности планеты. Корабль разрабатывался с целью максимально упростить колонизаторам первый выход в космос. Трюм корабля позволяет доставлять груз на орбиту и развивать торговлю с другими колониями. Корабль не защищен, не несет вооружения и приспособлен только для подъема на орбиту.'),
(7002, '<b>Средний шатл</b>\n\nСредний по вместимости шатл используется в основном для массовой доставки продуктов и ресурсов на орбиту. Очень выгоден для торговли на ранних этапах развития колонии. Учитывая, что антигравитационный двигатель не потребляет топливо, средний шатл заменяет флот из трех малых шатлов. Размер грузового отсека так же позволяет выводить на орбиту крупные конструкции, которые не входят в малый шатл.'),
(7003, '<b>Большой шатл</b>\n\nСамый грузоподъемный корабль из серии орбитальных шатлов. Используется только для доставки груза на орбиту. Не редко корабли объединяют во флот и для доставки большого количества груза на орбиту, где сборочный цех создает большие корабли. В отличии от других шатлов корпус покрыт простой броней, которая позволяет продержаться в бою некоторое время.'),
(7004, '<b>Разведчик</b>\n\nКорабль построен по принципу минимальной массы, поскольку радар установленный на корабле работает на гравитационных аномалиях пространства. Не смотря на мизерный грузовой отсек корабль способен перемещаться с огромными скоростями и обладает всеми тремя типами двигателей, что делает его очень удобным для перемещения игрока по мирным системам. Корабль способен засечь даже минимальную массу (равную своей) в любой точке звездной системы.\n\nДорабатывается до Разведчика-Д'),
(7007, '<b>Межпланетный шатл</b>\n\nРазрабатывая корабль для быстрых грузоперевозок в звездной системе ставилась цель с минимальными затратами получить максимально возможный по вместимости корабль. Большая часть используемых деталей применяется в шатле, отличительной особенностью является установленный межпланетный двигатель и термоядерный реактор. Этот корабль является настоящей рабочей лошадкой строителей и управленцев.'),
(9014, '<b>Межгалактический транспорт</b>\n\nКорабль обладает большой вместимостью грузовых отсеков, что позволяет перевозить множество устройств в трюме корабля. Основное предназначение корабля это транспортировка орбитальных конструкций. Не редко корабль используют в торговых операциях, однако корабль не обладает собственным вооружением, поэтому торговцы часто объединяют во флот несколько военных кораблей. Двигатели корабля потребляют среднее количество урана и водорода, при этом скорость корабля не высока. Большая часть энергии уходит на плавный разгон и плавное торможение. Ввиду большой массы корабль не маневренный.'),
(9015, '<b>Гиперактивный планетарный двигатель</b>\n\nВо время экспериментов с сильными магнитными и гравитационными полями ученые обнаружили свойство пространства скачкообразно менять размерность, сначала удалось реализовать пятимерное пространство, а затем и большее количество измерений. Изменения в пространстве сохраняются некоторое время, и тесты показали, что с увеличением размерности пространства увеличивается максимальная скорость с которой может перемещаться масса. При достижении семимерного пространства скорость стала неограниченной, и рост массы при ускорении не наблюдался вовсе. Это позволило создать гиперактивный двигатель, в основе которого лежит принцип резкого изменения пространства с последующим перемещением с неограниченной скоростью. При выходе в обычное пространство корабль должен находиться в состоянии покоя. Это позволило увеличить расстояния перемещения кораблей.\n\nДорабатывается до Межгалактического двигателя'),
(9016, '<b>Кабина транспортного корабля</b>\n\nКабина представляет собой симбиоз рубки управления и удобного спального места. Перелеты транспортного корабля это длительная процедура, иногда корабль находится неделями в дальних перелетах. В кабинах транспортных кораблей легко помещается до пяти человек, что делает дальние перелеты менее скучными. Профессиональные торговцы благоустраивают кабину настолько, что жить в ней им приятней, чем находиться на станции или на планете. Уровень защищенности кабины от космических лучей и радиации очень велик и позволяет комфортно себя чувствовать даже вблизи белых карликов.'),
(9017, '<b>Корпус среднего транспорта</b>\n\nКорпус представляет собой основную часть корабля, к которой крепятся все внутренние модули и блоки. Корпуса стандартизированы для удобства быстрой автоматической стыковки, а так же для погрузки и разгрузки товара.'),
(9018, '<b>Магнитнорезонансный щит</b>\n\nЩит, используемый на кораблях малого и среднего класса. Технологически представляет собой большое количество сбалансированных электромагнитов на сверхпроводниках. Позволяет отклонять или гасить скорость любой массы направленной на корабль благодаря локальному искажению магнитных полей. Щит не обладает инерцией, что позволяет отключать его на момент выстрела. Щит малопригоден для наземных построек из-за низкотемпературных сверхпроводников.'),
(9019, '<b>Топливно-грузовой отсек</b>\n\nОтсек представляет собой конструкцию из емкостей и помещений для хранения. Уровень прочности отсека позволяет транспортировать различные вещества без опасности их разрушения и порчи. Топливные приемника подключаются непосредственно к отсеку, что позволяет производить загрузку топлива в двигатели по мере надобности. Водород загружается в виде жидкости находящейся в камере переменного объема. Уран загружается как мелкодисперсная пыль урана и углерода, для начала ядерной реакции смесь разогревают до 12000 градусов и подвергают давлению, что вызывает формирование углеродной кристаллической решетки, силами которой начинается цепная ядерная реакция медленного горения.\n\nВместимость отсека: 5000'),
(9025, '<b>Истребитель</b>\n\nМалый истребитель обладает уникальным набором двигателей, что позволяет ему проявлять себя в качестве разведчика. На корабле установлен антигравитационный, межпланетный и гипер двигатель. Корабль способен нести вооружение и перемещаться в удаленные области вселенной. Однако из-за малой огневой мощи для завоевания одиночный корабль мало подходит. При объединении кораблей во флот происходит очень большой перерасход топлива на перемещения.\n\nДорабатывается до Истребителя-С'),
(9026, '<b>Корпус истребителя</b>\n\nБлагодаря двум сложным сплавам, один из которых обладает эффектом памяти, истребитель отлично ведет себя как в космосе, так и в атмосфере планеты. Весь корпус представляет собой подвижную скорлупу, которая принимает наиболее оптимальную форму в зависимости от температуры и условий окружающей среды. При попадании теплового излучения на корпус корабля корпус утолщается, передавая энергию на внутренние радиаторы.\nКорпус, не смотря на малый вес, обладает поистине фантастической устойчивостью, что позволяло неоднократно сохранить жизнь пилота.'),
(9027, '<b>Лазерная турель</b>\n\nЭто универсальное оружие, которое действует и в космическом пространстве и в атмосфере. Нанося малый урон, оружие отличается абсолютной меткостью на малых расстояниях. Данный тип вооружения очень легок и устанавливается на корабли любого типа. Из-за своих характеристик оружие часто применяется во время боев в атмосфере планеты.\nВпервые оружие было установлено на большой шатл, но из-за большой потребляемой мощности шатл при испытаниях был утерян. В настоящее время местонахождение шатла неизвестно. Все последующие типы лазеров устанавливаются только на кораблях с дублируемой системой питания.\n\nДорабатывается до Лазерного модуля'),
(9028, '<b>Кабина истребителя</b>\n\nКонструкция помимо кабины включает в себя простой боевой компьютер, который обеспечивает наведение турелей на цель. Радар корабля может применяться как в космосе, так и на поверхности планеты. За основу взята кабина среднего шатла, но из-за огромного количества военного оборудования кабина достаточно тесная и дальние перелеты в корабле событие малоприятное.'),
(9036, '<b>Квантовый модуль</b>\n\nИспользуя перегретую плазму из ионизированного водорода, а так же ускоритель на фотонной индукции атакует флот подлетающих кораблей волной из частиц. Общая энергия попадающая на корабль сравнима с многотонной нагрузкой. Прежде всего это приводит к истощению защиты кораблей, а затем разрушает конструкцию приводя к запредельным нагрузкам все устройства корабля.\n\nРазрабатывается из Квантовой турели'),
(9037, '<b>Лазерный модуль</b>\n\nИспользуется на больших орбитальных станциях и крупных кораблях уничтожителях. Модуль потребляет огромное количество энергии, которой хватает всего на несколько выстрелов. Из-за постоянного перегрева модуль можно использовать только в открытом космосе. В модуле используется импульсный лазер, который можно в последующем улучшить.\n\nРазрабатывается из Лазерной турели'),
(9038, '<b>Орбитальная платформа</b>\n\nПредставляет собой скелет из гигантских ферм. Платформа снабжена рычагами, магнитными двигателями поворота и импульсными двигателями коррекции орбиты. Платформа используется для орбитального базирования военных спутников. Основная запасная часть для сборки орбитального орудийного спутника.'),
(9039, '<b>Орбитальные наноботы</b>\n\nМелкие роботы размером в несколько десятков и сотен атомов. Используются в безвоздушном пространстве, так как имеют способность к свариванию любых поверхностей. Каждый нанобот снабжен собственным ионным двигателем, обладает малым термоядерным реактором и способен как к самостоятельным, так и к групповым действиям. Наноботы используются для точной подгонки устройств, для улучшения характеристик и другой работы в открытом космосе. Устройства не долговечны и не имеют возможности к саморепликации, что позволяет использовать их даже на вражеской территории без опасности попадания технологии в руки врага.'),
(9040, '<b>Орбитальный реактор</b>\n\nУстройство, производящее энергию получая ее из реакции аннигиляции. Однократной заправки устройства при производстве достаточно для работы в течении двух тысяч лет, что позволяет использовать устройства на удаленных военных станциях не переживая за энергоснабжение.\n\nМощность реактора: 150 ГВт'),
(9041, '<b>Плазменный модуль</b>\n\nИспользуется на орбитальных станциях, а также в крупных кораблях. Производит однократный выстрел за залп, каждый выстрел несет в себе разрушительную мощь. Плазма представляет собой поток перегретых газов, в которых течет постоянный ток по сверхпроводящей оболочке, генерирует собственное магнитное поле и удерживает плазму в замкнутом пространстве. При соприкосновении с объектом плазма передает всю содержащуюся в ней энергию объекту. Щит или электромагнитные ловушки снижают свою эффективность, любое вещество моментально испаряется.\n\nРазрабатывается из Плазменной турели\n\nДорабатывается до Плазменного индуктора'),
(9048, '<b>Корвет</b>\n\nКорвет представляет собой среднее звено военной техники. Объединенные во флот корабли способны поражать цели в любой точки галактики. Не редко данный тип кораблей используют для захвата планет. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах.'),
(9049, '<b>Аккумулятор плазмы</b>\n\nУстройство для накопления и поддержания высокой энергии в плазме. Используется в Плазменных реакторах, турелях, орудийных установках. Устанавливается на космические корабли ввиду невозможности генерации нужного количества плазмы в момент выстрела. Плазма генерируется в любое свободное время, однако в момент выстрела магнитные ловушки "отпускают" поток в заданном направлении. Устройство представляет собой четко сбалансированный магнитный щит вокруг накопительной камеры. Для поддержания сильного магнитного поля используются постоянные магниты с корректирующими переменными катушками.\n\nПобочный эффект используется в плазменных реакторах, камера накопления плазмы обладает сильным статическим зарядом, который используется для ионных двигателей.'),
(9050, '<b>Корпус корвета</b>\n\nКорпус корвета представляет собой составную чешуйчатую конструкцию выполненную из Титана легированного Неодимом. В каждом кристалле корпуса выстраивается собственная структура благодаря добавлению золота и молибдена на уровне отдельных атомов, что позволяет получить разные по упругости части конструкции. Корпус способен противостоять любым метеоритам, а так же отразить несколько выстрелов стандартного лазерного орудия. Обладая столь большой прочностью корпус не способен противостоять эрозии поверхности, поэтому для внешнего покрытия используется углеродистое волокно.'),
(9051, '<b>Нанозащитное покрытие</b>\n\nПокрытие представляет собой сплошной лист тонкого, но прочного материала. Основная составляющая покрытия углеродные кластеры и мономолекулярные цепочки. Атомарное легирование материала позволяет создавать искусственные центры напряжения, что делает материал очень эластичным. Покрытие очень устойчиво к жестким видам излучения, хорошо противостоит активным средам и способно испытывать большие температурные перегрузки. Предел прочности покрытия на разрыв до сих пор не выяснен до конца, поскольку оно прочнее любой металлической детали которые неизбежно использовались для испытаний.\n\nПокрытие обладает очень слабым поперечным сопротивлением, что позволяет выполнять выкройку любой формы. Для склеивания нет необходимости использовать сторонние реагенты, поскольку края разрезанного покрытия обладают свойством регенерации и сращиваются самостоятельно.'),
(9052, '<b>Плазменная турель</b>\n\nИспользуется на космических кораблях среднего калибра. Турель представляет собой устройство дульной наводки сгустка перегретой плазмы на цель. Плазма обладает колоссальной энергией, что позволяет наносить большой урон за выстрел. Учитывая относительно малую скорость перемещения плазмы в пространстве как правило устанавливают несколько независимых турелей. Турель не является орудием как таковым, выполняя лишь функции наведения и производство выстрела. Для полноценного орудия необходим как минимум один аккумулятор плазмы. Количество выстрелов за один залп зависит от количества аккумуляторов.\n\nДорабатывается до Плазменного модуля'),
(9060, '<b>Капитанский мостик</b>\n\nГлавная рубка средних и больших кораблей. С капитанского мостика осуществляется управление всем кораблем и командование боем. Несмотря на очень дорогое оформление драгоценными металлами, функциональность в дизайне стоит на первом месте. Внешняя защита позволяет выдержать радиоактивный фон любого космического боя.'),
(9061, '<b>Каюта экипажа</b>\n\nКаюта представляет собой помещение со всем необходимым для продолжительных космических перелетов. В каждой каюте может комфортно расположится до 3 человек. Полностью замкнутый внутренний цикл позволяет с одинаковой легкостью осуществлять конвоирование преступников или проживание высокопоставленных особ. Каюта обладает собственной защитой от радиации и системой жизнеобеспечения.'),
(9062, '<b>Корпус линкора</b>\n\nЛинкор относится к классу средних кораблей и обладает внушительной массой, ввиду чего не может приземляться на планеты, а также наносить удары по наземным постройкам. Корпус состоит из сложных молекулярных сплавов, которые способны выдерживать многотонные инерционные нагрузки. Поскольку Линкор не обладает антигравитационными двигателями, корпус подвержен эрозии в атмосфере, однако практически вечен в безвоздушном пространстве.'),
(9063, '<b>Межгалактический двигатель</b>\n\nДвигатель способен открывать проход в так называемое гиперпространство. С математической точки зрения корабль переводится в многомерное пространство, тем самым переводя скоростные ограничения специальной теории относительности в дополнительные три измерения, сняв ограничение на ускорение и скорость, корабль начинает постоянный разгон, а затем постоянное торможение. Побочным эффектом является отсутствие инерции и как следствие малые затраты на ускорение. Для работы двигателя требуется большое количество энергии, которая вырабатывается во время управляемого ядерного взрыва.\n\nРазрабатывается из Гиперактивного планетарного двигателя'),
(9064, '<b>Средний термоядерный реактор</b>\n\nРеактор производит большое количество энергии сравнимое с четырьмя малыми термоядерными реакторами, по сути, реактор представляет собой два малых термоядерных реактора объединенных в одном корпусе. Объединение позволило увеличить скорость набора мощности при том же расходе топлива. Во время активного набора мощности первый реактор является термоядерным нагнетателем энергии и вещества для второго реактора. Во втором реакторе реакция синтеза происходит уже между продуктами первого реактора. Загрузка реакторов топливом производится один раз во время изготовления, далее реактор способен проработать несколько тысяч лет (точный срок службы пока экспериментально не доказан).\n\nРазрабатывается из Малого термоядерного реактора\n\nДорабатывается до Большого термоядерного реактора\n\nМощность реактора: 150 ГВт'),
(9066, '<b>Линкор</b>\n\nЛинкор относится к среднему звену военных кораблей. Это сильно защищенный корабль, обладающий большой мощью, что позволяет уничтожать врага еще до того, как он произведет выстрел. Линкор хорошо справляется как с малыми, так и с большими целями, однако не способен самостоятельно нападать на планеты. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах. Скорость Линкора в реальном пространстве сравнима со скоростью корвета, однако в гиперпространстве Линкор потребляет большое количество урана и медленно перемещается.\n\nДорабатывается до Линкора-М'),
(9070, '<b>Фрегат</b>\n\nФрегат относится к среднему звену военных кораблей. Имея достаточно большую защиту способен долго простоять на поле боя, однако слабое вооружение не дает возможности атаковать крупные объекты. Фрегат наиболее эффективен против малых кораблей. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах. Скорость Фрегата в реальном пространстве сравнима со скоростью Корвета, однако в гиперпространстве фрегат потребляет большое количество урана и медленно перемещается.'),
(9071, '<b>Корпус фрегата</b>\n\nФрегат относится к классу средних кораблей и обладает внушительной массой, ввиду чего не может приземляться на планеты, а так же наносить удары по наземным постройкам. Корпус состоит из сложных молекулярных сплавов, которые способны выдерживать многотонные инерционные нагрузки. Поскольку Фрегат не обладает антигравитационными двигателями, корпус подвержен эрозии в атмосфере, однако практически вечен в безвоздушном пространстве.'),
(9074, '<b>Линкор - модифицированный</b>\n\nЛинкор относится к среднему звену военных кораблей. Это сильно защищенный корабль, обладающий большой мощью, что позволяет уничтожать врага еще до того, как он произведет выстрел. Линкор хорошо справляется как с малыми, так и с большими целями, однако не способен самостоятельно нападать на планеты. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах. Скорость Линкора в реальном пространстве сравнима со скоростью корвета, однако в гиперпространстве Линкор потребляет большое количество урана и медленно перемещается.\n\nВ отличии от базового Линкора на данном типе кораблей установлено всего одно орудие, но реализован синхронный выстрел плазмы, таким образом сила залпа поднялась почти вдвое, однако количество поражаемых целей сократилось до одной.\n\nРазрабатывается из Линкора\n\nДорабатывается до Линкора-Т');
INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(9076, '<b>Квантовая турель</b>\n\nИспользуя перегретую плазму из ионизированного водорода, а так же ускоритель на фотонной индукции турель производит выстрел по всем противникам за один залп. Общая энергия, попадающая на корабль, сравнима с многотонной нагрузкой. Прежде всего это приводит к истощению защиты кораблей, а затем разрушает конструкцию приводя к запредельным нагрузкам все устройства корабля. Чтобы не поражать союзников по шифрованному каналу связи передается точный момент залпа, что позволяет синхронизировать защиту корабля с производимым выстрелом.\n\nДорабатывается до Квантового модуля'),
(9079, '<b>Линкор - тяжелый</b>\n\nЛинкор относится к среднему звену военных кораблей. Это сильно защищенный корабль, обладающий большой мощью, что позволяет уничтожать врага еще до того, как он произведет выстрел. Линкор хорошо справляется как с малыми, так и с большими целями, однако не способен самостоятельно нападать на планеты. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах. Скорость Линкора в реальном пространстве сравнима со скоростью корвета, однако в гиперпространстве Линкор потребляет большое количество урана и медленно перемещается.\n\nВ отличии от базового Линкора на данном типе кораблей установлено всего одно орудие квантовой генерации частиц. Линкор приобрел большую массу, разработчикам пришлось отказаться от второго грузового отсека. Орудие линкора поражает все цели в радиусе за один залп. Не смотря на малую мощность поражения, суммарный выстрел может превзойти любой точечный вид оружия.\n\nРазрабатывается из Линкора-М'),
(9082, '<b>Бомбардировщик</b>\n\nБомбардировщик относится к типу тяжелых кораблей. Обладая очень большой огневой мощью он не способен самостоятельно перемещаться в галактике, поскольку  грузовой отсек не способен вместить достаточное количество топлива. Таким образом, бомбардировщик полезен только в составе флота. Количество орудий и способность приземляться на планете позволяют завоевывать планеты даже с очень слабым навыком бомбометания. Скорость перемещения корабля очень низкая из-за чего весь флот перемещается очень медленно.'),
(9084, '<b>Бомбовой отсек</b>\n\nОтсек используется на специальном типе кораблей. Отсек позволяет производить как точечную, так и ковровую бомбардировку планет. В космическом бою оружие малопригодно из-за малой скорости перемещения, а так же из-за малого количество энергии отдельного выстрела. Суммарный уровень атаки средний.\n\nРазрабатывается из Большого грузового отсека\n\nВместимость отсека: 8000'),
(9085, '<b>Упаковка кислорода</b>\n\nГазы не обладают большой плотностью, однако есть возможность создавать устойчивые искусственные структуры. Такие структуры сначала ошибочно были приняты за кристаллы, однако при нагревании газ легко выделяется из структуры. Малая скорость выделения газа единственное, что помешало использовать кристаллы в качестве топлива для кораблей. Однако перевозка газа в основном осуществляется в упакованном виде.'),
(9087, '<b>Упаковка водорода</b>\n\nГазы не обладают большой плотностью, однако есть возможность создавать устойчивые искусственные структуры. Такие структуры сначала ошибочно были приняты за кристаллы, однако при нагревании газ легко выделяется из структуры. Малая скорость выделения газа единственное, что помешало использовать кристаллы в качестве топлива для кораблей. Однако перевозка газа в основном осуществляется в упакованном виде.'),
(9089, '<b>Упаковка азота</b>\n\nГазы не обладают большой плотностью, однако есть возможность создавать устойчивые искусственные структуры. Такие структуры сначала ошибочно были приняты за кристаллы, однако при нагревании газ легко выделяется из структуры. Малая скорость выделения газа единственное, что помешало использовать кристаллы в качестве топлива для кораблей. Однако перевозка газа в основном осуществляется в упакованном виде.'),
(9090, '<b>Упаковка хлора</b>\n\nГазы не обладают большой плотностью, однако есть возможность создавать устойчивые искусственные структуры. Такие структуры сначала ошибочно были приняты за кристаллы, однако при нагревании газ легко выделяется из структуры. Малая скорость выделения газа единственное, что помешало использовать кристаллы в качестве топлива для кораблей. Однако перевозка газа в основном осуществляется в упакованном виде.'),
(9097, '<b>Корпус разведчика</b>\n\nНаиболее сложная деталь корабля. Корпус представляет собой очень не прочную скорлупу, которая обладает уникальной способностью пропускать через себя гравитационные волны без искажений.'),
(9098, '<b>Радар</b>\n\nУстройство позволяет сканировать пространство всеми доступными способами. Для большей скорости сканирования применяется гравитационный метод определения смещения масс. Из картины гравитационных волн исключаются все относительно статичные объекты, а так же известные планеты, спутники и метеориты. Оставшиеся объекты представляют собой как правило корабли. Картина, полученная с помощью радара, отображает все корабли, присутствующие в звездной системе.\n\nДля работы радару необходимо находится на некотором удалении от больших масс, поэтому он не работает на планетах и орбитах планет.'),
(9101, '<b>Уничтожитель</b>\n\nУничтожитель относится к звену больших военных кораблей. Это сильно защищенный корабль, обладающий колоссальной мощью главного калибра. Корабль способен одним залпом уничтожить орбитальную конструкцию. Защита корабля позволяет долгое время оставаться в бою. Уничтожитель наиболее эффективен против средних и больших кораблей и орбитальных конструкций. Грузовой отсек способен вмещать в себя целый флот малых кораблей и значительные запасы топлива. Скорость Уничтожителя средняя между бомбардировщиком и линкором.'),
(9103, '<b>Фотонный двигатель</b>\n\nЭнергетически независимый модуль производящий огромное количество кинетической энергии. Двигатель основан на принципе максимального использования массы. Термоядерные реакторы входящие в комплект двигателя используются для получения антивещества, вырываясь из магнитной ловушки антивещество истекает в фокус зеркала из нанозащитного покрытия, после аннигиляции полученная энергия разгоняет корабль.'),
(9105, '<b>Плазменный индуктор</b>\n\nНезависимый блок выработки и концентрации плазмы, полностью самостоятельный модуль, не требующий энергии или управления. Плазма генерируется всегда с момента запуска корабля, в случае необходимости ловушки просто выпускают накопленную плазму в заданном направлении и продолжают процесс накопления. Максимально возможная энергия импульса варьируется в зависимости от орудия испускания.\n\nРазрабатывается из Плазменного модуля\n\nДорабатывается до Плазмотрона'),
(9107, '<b>Несущая конструкция</b>\n\nПо своей сути скелет корабля. Состоит из набора стандартизированных балок и перекрытий, что позволяет использовать одну и ту же несущую конструкцию в разных кораблях. Все оборудование корабля крепится непосредственно к несущей конструкции, что обеспечивает большую надежность в сравнении с корпусным расположением оборудования. Сплавы материалов изготавливаются непосредственно в космосе, что позволяет строить огромные корабли на орбитальных базах. При проектировании крупных кораблей, следует учитывать, что несущая конструкция имеет малую поперечную прочность и мало пригодна для кораблей планетарного базирования.'),
(9109, '<b>Нос уничтожителя</b>\n\nНосовая часть уничтожителя, прежде всего это главный калибр. Вдоль всего носа корабля расположено дуло плазмотрона. Все оборудование прицеливания и производства выстрела находится в носовой части корабля. Поскольку на момент выстрела щит отключается, носовая часть представляет собой очень прочный слой брони.'),
(9111, '<b>Корма уничтожителя</b>\n\nВ кормовой части корабля расположены все каюты экипажа, поэтому эта часть корабля максимально защищена от всех видов вредного излучения. Так же тут находится кают компания и различные информационные залы. Корма крепится непосредственно на несущую конструкцию. В корме так же находятся теплоотводы от фотонного двигателя.'),
(9113, '<b>Гравитационный щит</b>\n\nНезависимый модуль защиты крупных объектов. Изначально разрабатывался как планетарный щит орбитального базирования, однако из-за большого потребления энергии не удалось использовать даже на малых лунах. В настоящее время встречается очень редко, в основном на очень больших кораблях. Принцип действия основан на изменении течения времени в гравитационном поле, вокруг объекта создается несколько виртуальных поверхностей с различной гравитацией, что превращает поверхность гравитационного пузыря в линзу, таким образом, выстрелы направленные в корабль по касательной огибают его или отражаются, а выстрелы произведенные под прямым углом равномерно рассеиваются по всему корпусу корабля не причиняя ущерба. Щит обладает огромной инерцией отключения из-за малого угла рассеивания гравитационного поля, поэтому устанавливать подобный щит на скорострельные корабли не имеет смысла.'),
(9115, '<b>Потоковый плазмотрона</b>\n\nПредставляет собой плазменную турель, увеличенную почти в четыре раза. Орудие является главным калибром на уничтожителе. Позволяет пропускать энергию до 8000 единиц. Во время выстрела турель испытывает большие термические нагрузки из-за чего невозможно произведение нескольких выстрелов из одной турели. Исторически зарегистрирован случай установки пиратами турели на транспортный корабль, в итоге корабль, потеряв всяческую маневренность и не обладая защитой, был способен перемещаться только в составе флота и наносить сокрушительный выстрел. Однако из-за отсутствия брони являлся одноразовым кораблем.\n\nРазрабатывается из Плазменного индуктора'),
(9117, '<b>Большой термоядерный реактор</b>\n\nРеактор производит большое количество энергии. Объем сгорания вещества сравним с четырьмя средними термоядерными реакторами, при этом количество полезной энергии в десятки раз больше. Загрузка реакторов топливом производится один раз во время изготовления, далее реактор способен проработать несколько тысяч лет (точный срок службы пока экспериментально не доказан).\n\nРазрабатывается из Среднего термоядерного реактора\n\nМощность реактора: 300 ГВт'),
(9118, '<b>Модуль удаленного управления</b>\n\nПриемно-передающий модуль работает на гравитационных волнах и способен моментально передавать информацию на неограниченное расстояние. Используется для управления планетами и орбитами. Модуль устанавливается на корабль который используется в качестве ресивера для гравитационных и радиоволн. Модуль способен работать на любой планете, однако искусственно внесено ограничение на планеты с капсулой, где модуль не работоспособен.'),
(9119, '<b>Модуль удаленного управления</b>\n\nПриемно-передающий модуль работает на гравитационных волнах и способен моментально передавать информацию на неограниченное расстояние. Используется для управления планетами и орбитами. Модуль устанавливается на корабль, который используется в качестве ресивера для гравитационных и радиоволн. Модуль способен работать на любой планете, однако искусственно внесено ограничение на планеты с капсулой, где модуль не работоспособен.'),
(9121, '<b>Корпус корабля удаленного управления</b>\n\nВ качестве корпуса используется несколько слоев брони, поскольку самая важная часть корабля находится внутри корпуса.'),
(9122, '<b>Корабль удаленного управления</b>\n\nКорабль используется для удаленного управления планетами и орбитами. Принцип действия модуля не раскрывается, однако допускается ограниченное использование подобных кораблей. Уровень защищенности корабля максимален. Учитывая ценность модуля удаленного управления, как правило, корабль сопровождает достаточно большой флот, обеспечивая безопасность на всем этапе перемещения.'),
(9302, 'По своей сути представляет дополнительный порт для подключения обучающих устройств. Имплантант удалось изготовить после того, как нейрохирурги нашли возможность изменять потоки сигналов в головном мозге. По сути этот имплантант это искусственное введение человека в состояние контролируемой шизофрении с раздвоением личности. После обучения личности складываются. Отрицательных побочных эффектов не выявлено. Условно положительный побочный эффект это ускорение изучения навыков.\n\nПозволяет изучать еще один навык параллельно\nСкорость изучения навыков увеличивается на 5%25'),
(9303, 'Имплантант.\n\nПо своей сути представляет дополнительный порт для подключения обучающих устройств. Имплантант удалось изготовить после того, как нейрохирурги нашли возможность изменять потоки сигналов в головном мозге. По сути этот имплантант это искусственное введение человека в состояние контролируемой шизофрении с раздвоением личности. После обучения личности складываются. Отрицательных побочных эффектов не выявлено. Условно положительный побочный эффект это ускорение изучения навыков.\n\nПозволяет изучать еще один навык параллельно\nСкорость изучения навыков увеличивается на 5%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9124, '<b>Корабль удаленного управления</b>\n\nКорабль используется для удаленного управления планетами и орбитами. Принцип действия модуля не раскрывается, однако допускается ограниченное использование подобных кораблей. Уровень защищенности корабля максимален. Корабль способен перемещаться только в составе флота, потому что отсутствует грузовой отсек. Учитывая ценность модуля удаленного управления, как правило, корабль сопровождает достаточно большой флот, обеспечивая безопасность на всем этапе перемещения.'),
(9129, '<b>Истребитель - модифицированный</b>\n\nИстребитель обладает полным набором двигателей, что позволяет ему проявлять себя в качестве разведчика. На корабле установлен антигравитационный, межпланетный и гипер двигатель. Корабль способен нести вооружение и перемещаться в удаленные области вселенной. В отличии от первой модели установлено дополнительно 2 турели, однако пришлось пожертвовать размером грузового отсека.\n\nРазрабатывается из Истребителя\n\nДорабатывается до Истребителя-Т'),
(9130, '<b>Истребитель - тяжелый</b>\n\nТретье поколение истребителей разрабатывалось по запросам, поступающим от армейского командования. В первую очередь была увеличена огневая мощь. Лазерные турели заменили плазменной установкой. Полностью переработан механизм защиты. Грузовой отсек вообще исключили, так как истребители вне флота не представляют ценности. В результате получился достаточно прочный и сильный вид кораблей отлично подходящий для сопровождения крупных флотов.\n\nРазрабатывается из Истребителя-М'),
(9132, '<b>Ионный двигатель</b>\n\nПринцип действия ионного двигателя был давно известен и использовался на малых спутниках для корректировки орбиты. Данный тип двигателей обладает не очень большими характеристиками разгона и не может использоваться на кораблях, которым необходима скорость и маневренность, однако двигатель не потребляет топливо во время работы, что позволяет использовать его неограниченное время.\n\nРазрабатывается из Диффузного двигателя'),
(9133, '<b>Разведчик дальний</b>\n\nКорабль построен по принципу минимальной массы, поскольку радар установленный на корабле работает на гравитационных аномалиях пространства. Не смотря на мизерный грузовой отсек корабль способен перемещаться на большие расстояния и обладает всеми тремя типами двигателей. Корабль способен засечь даже минимальную массу (равную своей) в любой точке звездной системы. В отличии от простого радарного корабля в дальнем корабле снижено потребление урана вдвое, а благодаря новому ионному двигателю потребление водорода нет совсем, однако скорость перемещения в реальном пространстве упала в 100 раз.\n\nРазрабатывается из Разведчика'),
(9138, '<b>Штурмовик</b>\n\nКорабль используется в основном как патрульный катер. Обладая колоссальной защитной броней и малым потреблением топлива корабль способен долгое время находиться в патруле, охраняя реальные пространства. Неоднократно было замечено, что штурмовики использовались при нападении на удаленные системы, однако корабль авианосец способный перевезти груз такой массы, точно не установлен. В отличии от патрульного катера на корабле не установлен радар, поскольку во время боевых испытаний было выявлено, что противник легко находит корабли с установленными активными радарами. Для нормальной работы используется отдельный радарный корабль в режиме пассивного сканирования.'),
(9139, '<b>Корпус штурмовика</b>\n\nКорпус обладает способностью противостоять достаточно большим нагрузкам. По сути своей корабль планировался как танк, способный не очень быстро передвигаться в реальном пространстве. Из-за большого количества слоев брони корабль практически не снижает скорости при входе в атмосферу, что создает красивый эффект посадки в виде огненного болида.'),
(9143, '<b>Тритий</b>\nРедкий химический элемент, содержится в малых количествах в <u><a href=''page.php?id=6%26itm=Тритит К''>Трититах</a></u> добывается из них путем переработки. Необходим для модуля гиперперехвата.'),
(9144, '<b>Трититы</b>\n\nДолгое время неизвестная науке раса, представляющая собой неорганическую форму жизни. На сегодняшний день это единственные обитатели открытого космоса. Трититы способны перехватывать корабли выходящие из гиперпространства. Питаются Трититы радиацией выделяемой звездами и особенно взрывами сверхновых. Долгое время нападения на мирные корабли оставались необъяснимыми, однако после захвата в плен первого Тритита стало понятно, что именно радиация внутреннего реактора привлекает Трититов. Поскольку существа не обладают разумом и по уровню развития ближе к одноклеточным их присутствие в обитаемых мирах крайне нежелательно, а природа их поведения приравнивается к паразитирующей. Уничтожение или захват Трититов поощряется Конфедерацией. После захвата есть возможность добыть Тритий, который используется в устройстве гиперперехвата.\n\nДанный вид Трититов является самым слабым представителем расы, однако даже он способен уничтожить перехваченный транспортный корабль.\n'),
(9147, '<b>Трититы С</b>\n\nДолгое время неизвестная науке раса, представляющая собой неорганическую форму жизни. На сегодняшний день это единственные обитатели открытого космоса. Трититы способны перехватывать корабли выходящие из гиперпространства. Питаются Трититы радиацией выделяемой звездами и особенно взрывами сверхновых. Долгое время нападения на мирные корабли оставались необъяснимыми, однако после захвата в плен первого Тритита стало понятно, что именно радиация внутреннего реактора привлекает Трититов. Поскольку существа не обладают разумом и по уровню развития ближе к одноклеточным их присутствие в обитаемых мирах крайне нежелательно, а природа их поведения приравнивается к паразитирующей. Уничтожение или захват Трититов поощряется Конфедерацией. После захвата есть возможность добыть Тритий, который используется в устройстве гиперперехвата.\n\nДанный вид Трититов является средним по силе представителем расы, однако даже он способен уничтожить перехваченный транспортный корабль.\n'),
(9150, '<b>Трититы Т</b>\n\nДолгое время неизвестная науке раса, представляющая собой неорганическую форму жизни. На сегодняшний день это единственные обитатели открытого космоса. Трититы способны перехватывать корабли выходящие из гиперпространства. Питаются Трититы радиацией выделяемой звездами и особенно взрывами сверхновых. Долгое время нападения на мирные корабли оставались необъяснимыми, однако после захвата в плен первого Тритита стало понятно, что именно радиация внутреннего реактора привлекает Трититов. Поскольку существа не обладают разумом и по уровню развития ближе к одноклеточным их присутствие в обитаемых мирах крайне нежелательно, а природа их поведения приравнивается к паразитирующей. Уничтожение или захват Трититов поощряется Конфедерацией. После захвата есть возможность добыть Тритий, который используется в устройстве гиперперехвата.\n\nДанный вид Трититов является самым сильным представителем расы, он способен уничтожить перехваченный транспортный корабль.\n'),
(9152, '<b>Патрульный катер</b>\n\nПосле того, как в обитаемых мирах начали появляться Трититы, конфедерация решила снабжать колонистов простым, но надежным устройством по поиску и уничтожению противника. Катер способен самостоятельно проводить рейды, требуя малое количество топлива и обладая радаром.'),
(9153, '<b>Патрульный катер</b>\n\nПосле того, как в обитаемых мирах начали появляться Трититы конфедерация решила снабжать колонистов простым, но надежным устройством по поиску и уничтожению противника. Катер способен самостоятельно проводить рейды требуя малое количество топлива и обладая радаром.'),
(9155, '<b>Лазерная пушка</b>\n\nПростое в сборке и надежное в бою оружие было специально разработано для установки на патрульные катера. Поскольку катер представляет собой малый шатл, с установленным планетарным двигателем и укрепленной броней, при разработке учитывалось малое энергопотребление, и старались добиться наименьшей возможной массы. Из-за малых убойных качеств оружие устанавливается только на патрульные катера.'),
(9156, '<b>Модуль гиперперехвата</b>\n\nПосле появления Трититов их удалось отловить и исследовать. Ученые пришли к выводу, что именно тритий и улавливаемый ими дейтерий при определенных условиях изменяет пространственную картину так, что корабль, выходящий из многомерного пространства, оказывается в непосредственной близости от Тритита. Высказывались даже предположения, что Трититы разумны или когда-то существовали другие существа, способные перемещаться в гиперпространстве. Однако ученые разобрались в природе явлений и смогли смоделировать данное событие, так появился модуль гиперперехвата. В реальности модулем чаще всего пользуются пираты, однако согласно закону о свободной торговле конфедерация не вправе запрещать торговать каким бы то ни было устройством.'),
(9157, '<b>Модуль гиперперехвата</b>\n\nПосле появления Трититов их удалось отловить и исследовать. Ученые пришли к выводу, что именно тритий и улавливаемый ими дейтерий при определенных условиях изменяет пространственную картину так, что корабль, выходящий из многомерного пространства, оказывается в непосредственной близости от Тритита. Высказывались даже предположения, что Трититы разумны или когда-то существовали другие существа, способные перемещаться в гиперпространстве. Однако ученые разобрались в природе явлений и смогли смоделировать данное событие, так появился модуль гиперперехвата. В реальности модулем чаще всего пользуются пираты, однако согласно закону о свободной торговле конфедерация не вправе запрещать торговать каким бы то ни было устройством.'),
(9159, '<b>Гиперперехватчик</b>\n\nКорабль построен на базе фрегата, поскольку у этого корабля достаточно свободного места и прочный корпус. Гиперперехватчик можно использовать как обычный военный корабль, однако отличительной способностью корабля является способность перехватывать выходящие из гиперпространства корабли. Перехватывая корабль, пространство искажается таким образом, что все линии выхода в реальность ведут в одну точку пространства. Пилот, чей корабль был перехвачен, может заметить перехват по искаженной точки выхода в реальный космос, однако никак не может отменить это действие.'),
(9163, '<b>Авианосец</b>\n\nСамый грузоподъемный корабль в галактике. Используется, как правило, в торговых операциях для купли и продажи кораблей, а так же в военных операциях для экономии топлива при доставке войск. Авианосец имеет внешнюю палубу для складирования груза, поэтому вместимость товара значительно превышает его собственный вес. Не имея собственного вооружения, требует обязательного сопровождения при длительных перелетах.'),
(9165, '<b>Палуба авианосца</b>\n\nВнешний модуль для крепления кораблей и других грузов. Используется в авианосцах для значительного увеличения грузоподъемности корабля. Из-за своей внешней конструкции способна вмещать груз массой больше корабля.\n\nДорабатывается до Дока стыковки');
INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(9166, '<h3>Собрание ЧАсто задаваемых ВОпросов</h3>\n\n<b>Где посмотреть ресурсы</b>\nПланетарные постройки: Капсула, Электростанция, Склад\nОрбитальные постройки: Торговая станция, Орбитальное хранилище, Солнечная электростанция, Геологический спутник\nЗакладка "Использовать".\n\n<b>Можно ли атаковать родную планету?</b>\nРодная планета и родная орбита находится под охраной конфедерации эти объекты атаковать нельзя. Ограбить чужую торговую станцию тоже нельзя. Атаковать любой корабль на орбите зеленой планеты тоже нельзя.\n\n<b>Где взять кредиты</b>\nКредиты можно заработать, выполняя задания или занимаясь торговлей.\n\n<b>Где взять конфедераты</b>\nВ меню "персонаж" или в меню "торговля" - "конфедерация" есть ссылка на покупку конфедератов.\n\n<b>Что делать если кончился водород</b>\nЕсли вы не рассчитали топливо, улетели далеко от планет и теперь не можете вернуться, то вам необходим заправщик. Для этого возьмите любой свободный корабль, заправьте его водородом и летите к тому кораблю, в котором кончилось топливо. Когда корабли окажутся в одной точке, объедините их во флот. С этого момента будет расходоваться топливо из заправщика. Если у вас нет свободного корабля, можно купить в конфедерации, купленный у конфедерации корабль появится на вашей торговой станции.\n\n<b>Как заправить корабль</b>\nДля заправки корабля необходимо топливо. Для перемещений внутри системы это водород, для гиперперехода уран. Чтобы заправить корабль топливом с планеты необходимо, чтобы корабль находился на планете в расконсервированном виде. В закладке "Склад" корабль отображается слева вверху. Слева внизу будут все доступные места для перемещения (по умолчанию выбрана сама планета). Справа внизу выберите топливо (водород или уран) затем в среднее окно введите количество и нажмите "Переместить". Либо после выбора топлива можно сразу нажать "Переместить все" - тогда переместится максимально возможное количество.\n\n<b>Что я получу выполнив задания</b>\nВыполняя задания, вы увеличиваете статус в обществе, однако, отказавшись от задания или выполнив его неправильно вы уменьшаете свой статус. Отрицательный статус говорит о том, что вы не законопослушный гражданин галактики.\n\n<b>Флот</b>\nЧтобы объединить корабли во флот достаточно выделить несколько кораблей, находящихся в одном месте. Для этого можно воспользоваться клавишей CTRL или Shift. В списке приказов появится "Объединить во флот". Если приказа нет, значит, корабли находятся в разных местах.\n\n<b>Радар</b>\nЛюбой корабль, на котором установлен радар, может находить и отображать на карте системы чужие корабли. Для этого надо, чтобы корабль с радаром находился в свободной точке пространства (не на орбите планеты). После этого, при перемещении в системе будут видны ваши корабли (отмеченные зеленым цветом) и чужие корабли (отмеченные желтым цветом).\n\n<b>Корабль не хочет лететь</b>\nДля перемещения кораблю нужно топливо. Для полетов в обычном пространстве требуется водород, в гиперпространстве требуется уран. Каждый корабль потребляет разное количество топлива. Если при выборе точки перемещения количество подсвечивается зеленым - топлива хватит в оба конца, если желтым - топлива не хватит на обратную дорогу, если красным - топлива не хватит для перемещения.\n\n<b>Что означает цвет ника в чате</b>\nЦвет ника говорит о статусе игрока: белый - нейтральный статус, зеленый - положительный статус, красный - отрицательный статус. В случае отрицательного статуса рядом с ником присутствует сумма, которую конфедерация выплатит любому, кто атакует объекты этого игрока. Номинально такой игрок причисляется к пиратам.\n\n<b>Потерянные корабли</b>\nВ галактике есть потерянные корабли. В среднем каждые стандартные сутки теряется 4 корабля. Любой, кто найдет такой корабль, может присвоить его себе. Имя таких кораблей определяется вашим бортовым компьютером как Abandon. Причины потери корабля, как правило неизвестны, возможно это было нападение пиратов.\n\n<b>Захват корабля</b>\nВо время боя есть возможность захватить корабль противника, для этого необходимо быть пиратом (статус ниже нуля) или изучить навык Абордаж (как его изучить описано в конспекте "Обучение")\n\n<b>Как захватить Тритита</b>\nДля захвата необходимо изучить навык "Абордаж" или быть пиратом. После захвата Тритита его необходимо законсервировать, проще всего это сделать на своей торговой станции, тем более, что Трититы не потребляют топливо для перемещения. После консервации необходимо доставить Трититов на поверхность в трюме любого корабля. Затем используя нанодиспенсер необходимо разобрать Тритита и получить Тритий.'),
(9168, '<b>Истребитель странников</b>\n\nПервый такой корабль был обнаружен на поверхности одной из планет. С планеты эвакуировали все население, а корабль в срочном порядке окружили другими истребителями. После двухнедельного наблюдения к кораблю разрешили подойти ученым и инженерам. Во многом корабль схож с техникой которую производит человечество, было даже мнение, что это обычный истребитель который в далеком будущем вышел из гиперпространства на сверхсветовой скорости и его перенесло в прошлое. С большим трудом технологии поддавались объяснению, однако именно эта находка позволила науке конфедерации далеко продвинутся в плане космического кораблестроения. В настоящий момент Макеты и чертежи остаются частью секретной доктрины, однако находки таких кораблей уже никого не удивляют.'),
(9169, '<b>Истребитель странников</b>\n\nПервый такой корабль был обнаружен на поверхности одной из планет. С планеты эвакуировали все население, а корабль в срочном порядке окружили другими истребителями. После двухнедельного наблюдения к кораблю разрешили подойти ученым и инженерам. Во многом корабль схож с техникой которую производит человечество. Было даже мнение, что это обычный истребитель, который в далеком будущем вышел из гиперпространства на сверхсветовой скорости и его перенесло в прошлое. С большим трудом технологии поддавались объяснению, однако именно эта находка позволила науке конфедерации далеко продвинутся в плане космического кораблестроения. В настоящий момент макеты и чертежи остаются частью секретной доктрины, однако находки таких кораблей уже никого не удивляют.\n\nВвиду секретности данной технологии копирование макета запрещено.'),
(9173, '<b>Глюонный реактор</b>\n\nДанный тип реакторов способен вырабатывать энергию и совершенно другого уровня материи. По сути, энергия производится даже не из материи как таковой, а из структуры самого пространства, в котором находится материя. Длительные эксперименты пока не привели к результатам, реактор не удается сделать больших размеров, не получается получить больше энергии, однако для своей массы это пока лучший реактор который известен человечеству. Учитывая, что реактор был установлен на одном из первых найденных кораблей странников это далеко не пик их цивилизации.\n\nВвиду секретности данной технологии копирование чертежа запрещено.\n\nМощность реактора: 270 ГВт'),
(9174, '<b>Гипердвигатель странников</b>\n\nВо многом технологии странников превзошли существующие ныне образцы. Если бы не найденный однажды корабль с чертежами, ученым никогда не удалось бы создать такой же легкий и производительный двигатель. Не считая того, что принцип действия двигателя странников и всех существующих двигателей одинаковый, все остальное полностью отличается от технологий наших дней.\n\nВвиду секретности данной технологии копирование чертежа запрещено.'),
(9175, '<b>Планетарный двигатель странников</b>\n\nДвигатель, как и все известные двигатели, работает на принципе ускорения водорода, однако скорость исходящего потока в этом двигателе настолько оптимально подобрана, что ионы водорода, разгоняясь до около световой скорости, обладают намного большей массой, чем в обычном планетарном двигателе. Однако использование данных двигателей на гражданских кораблях строго запрещено ввиду сильного радиационного фона во время работы двигателя.\n\nВвиду секретности данной технологии копирование чертежа запрещено.'),
(9177, '<b>Охотник странников</b>\n\nВпервые корабль был обнаружен в открытом космосе в облаке трития, дейтерия и водорода. После исследования смеси газов ученые предположили, что произошел бой между Трититами и кораблем типа корвет, однако судя по анализу распада трития бой произошел около 15000 лет назад. Корпус корабля идентичен корпусу который используется в кораблях типа корвет, однако после разбора корабля выяснилось, что это совершенно иной тип корабля. Помимо усиленного вооружения были найдены уже известные ученым глюонный реактор и двигатели неизвестной цивилизации Странников. Корабль так же был снабжен радаром и видимо использовался Странниками как корабль-охотник. Ученые до сих пор бьются над вопросом произошел ли бой действительно так давно или в результате какого-то катаклизма обоих противников забросило в далекое прошлое.'),
(9178, '<b>Охотник странников</b>\n\nВпервые корабль был обнаружен в открытом космосе в облаке трития, дейтерия и водорода. После исследования смеси газов ученые предположили, что произошел бой между Трититами и кораблем типа корвет, однако судя по анализу распада трития, бой произошел около 15000 лет назад. Корпус корабля идентичен корпусу, который используется в кораблях типа корвет, однако после разбора корабля выяснилось, что это совершенно иной тип. Помимо усиленного вооружения были найдены уже известные ученым глюонный реактор и двигатели неизвестной цивилизации Странников. Корабль так же был снабжен радаром и видимо использовался Странниками как корабль-охотник. Ученые до сих пор бьются над вопросом, произошел ли бой действительно так давно или в результате какого-то катаклизма обоих противников забросило в далекое прошлое.'),
(9179, '<b>Авианосец странников</b>\n\nСамый грузоподъемный корабль в галактике. Используется, как правило, в торговых операциях для купли и продажи кораблей, а так же в военных операциях для экономии топлива при доставке войск. Авианосец имеет внешнюю палубу для складирования груза, поэтому вместимость товара значительно превышает его собственный вес. Не имея собственного вооружения, требует обязательного сопровождения при длительных перелетах. Странники разработали уникальную технологию синхронизации антигравитационных двигателей, которую до сих пор не удалось перенести на другой корабль. Таким образом это самый грузоподъемный корабль способный приземлится на поверхность планеты.'),
(9181, '<b>Авианосец странников</b>\n\nСамый грузоподъемный корабль в галактике. Используется, как правило, в торговых операциях для купли и продажи кораблей, а так же в военных операциях для экономии топлива при доставке войск. Авианосец имеет внешнюю палубу для складирования груза, поэтому вместимость товара значительно превышает его собственный вес. Не имея собственного вооружения, требует обязательного сопровождения при длительных перелетах. Странники разработали уникальную технологию синхронизации антигравитационных двигателей, которую до сих пор не удалось перенести на другой корабль. Таким образом это самый грузоподъемный корабль способный приземлится на поверхность планеты.'),
(9185, '<b>Антирадар</b>\n\nУстройство было изначально разработано странниками. Ученым конфедерации удалось скопировать некоторые принципы его работы, однако по мощности оно значительно уступает кораблям странников. Долгое время не удавалось найти корабли с данным устройством ввиду их большой скрытности. Принцип работы устройства очень прост, внутри магнитной ловушки синтезируется вещество обладающее отрицательной массой равной массе корабля (или флота) таким образом суммарная масса становится нулевой и искажение пространства, улавливаемое радаром, не наблюдается.'),
(9187, '<b>Корабль прикрытия</b>\n\nКорабль способен скрыть свое пребывание в системе. При объединении такого корабля в флот весь флот становится невидим для радара. Чем больше таких кораблей в флоте, тем больше вероятность стать невидимым. Если в системе есть 1 радарный корабль, то достаточно 1 корабля прикрытия в флоте. При наличии 15 радарных кораблей - необходимо минимум 15 кораблей прикрытия в составе одного флота.'),
(9198, '<b>Разведчик странников</b>\n\nКорабль построен по принципу минимальной массы, поскольку радар установленный на корабле работает на гравитационных аномалиях пространства. Не смотря на мизерный грузовой отсек корабль способен перемещаться с огромными скоростями и обладает всеми тремя типами двигателей, что делает его очень удобным для перемещения игрока по мирным системам. Корабль способен засечь даже минимальную массу (равную своей) в любой точке звездной системы. Как и другие корабли этой древней расы технологически не все модули можно воспроизвести.'),
(9200, '<b>Радар странников</b>\n\nУстройство позволяет сканировать пространство всеми доступными способами. Для большей скорости сканирования применяется гравитационный метод определения смещения масс. Из картины гравитационных волн исключаются все относительно статичные объекты, а так же известные планеты, спутники и метеориты. Оставшиеся объекты представляют собой как правило корабли. Картина, полученная с помощью радара, отображает все корабли, присутствующие в звездной системе. Странники смогли сделать более чувствительный радар, который превосходит стандартный в 10 раз, это позволяет найти корабли находящиеся под прикрытием.\n\nДля работы радару необходимо находится на некотором удалении от больших масс, поэтому он не работает на планетах и орбитах планет.'),
(9202, '<b>Антирадар странников</b>\n\nУстройство было изначально разработано странниками и долгое время не удавалось повторить в точности его способности. Принцип работы устройства очень прост, внутри магнитной ловушки синтезируется вещество обладающее отрицательной массой равной массе корабля (или флота) таким образом суммарная масса становится нулевой и искажение пространства, улавливаемое радаром, не наблюдается. Антирадар странников до сих пор используется конфедерацией на своих военных кораблях.'),
(9205, '<b>Невидимка странников</b>\n\nДолгое время корабли не поддавались находке. В одной случайной экспедиции удалось обнаружить такой корабль визуально, после осмотра корабля он был доставлен на базу конфедерации, где был полностью демонтирован. Коэффициент искажения у корабля равен 10, необходимо минимум 11 радарных кораблей, что бы заметить флот под прикрытием этого корабля. При объединении такого корабля в флот весь флот становится невидим для радара. Чем больше таких кораблей в флоте, тем больше вероятность стать невидимым. Если в системе есть до 10 радарных кораблей, то достаточно 1 невидимки странников в флоте.'),
(9208, '<b>Штурмовик странников</b>\n\nКорабль долгое время не удавалось захватить, поскольку корабль, как правило, находился в активной защите и уничтожал всех, кто пытался приблизится. Корабль удалось взять на абордаж используя бесчисленное скопление мелких кораблей трититов. Пока Трититы отвлекали основные силы противника, корабль взяла под свой контроль абордажная команда. В настоящий момент корабль доступен для покупки, однако заполучить макет корабля почти невозможно.'),
(9218, '<b>Ракета апокалипсис</b>\n\nСамое сильное вооружение в космосе. Большинство кораблей могут быть уничтожены даже частью этой энергии. Если вы запускаете ракету апокалипсис и напротив вас не уничтожитель, будьте уверены корабль будет уничтожен кем бы он не был.\n\nТип ракеты: 9\nВзрывная сила: 4000'),
(9219, '<b>Ракета москит</b>\n\nОдна из первых разработок. Ракета используется для защиты транспортных кораблей от трититов. В большинстве случаев ракета позволяет уничтожить небольшой пиратский флот. После изобретения этой ракеты торговцы вздохнули с облегчением.\n\nТип ракеты: 1\nВзрывная сила: 25'),
(9220, '<b>Ракета оса</b>\n\nРакета составляет основу малого боевого флота. Обладает достаточной силой что бы помочь слабому кораблю противостоять даже кораблям классом выше. Количество ракет на корабле зависит только от места в трюме.\n\nТип ракеты: 2\nВзрывная сила: 50'),
(9221, '<b>Ракета смерч</b>\n\nРакеты были найдены в брошенном транспортном корабле, предположительно это разработка странников. Количество выдаваемой энергии просто поражает. Не многие корабли смогут противостоять флоту с таким вооружением.\n\nТип ракеты: 8\nВзрывная сила: 2500'),
(9222, '<b>Ракета стрекоза</b>\n\nРакета входит по классу в флот средней силы. Многие корабли используют ее для экономии времени в бою. По параметрам ракета позволяет защитить корабль от незваных гостей, а так же предотвратить долгие перестрелки с трититами.\n\nТип ракеты: 4\nВзрывная сила: 150'),
(9223, '<b>Ракета тайфун</b>\n\nРакета составляет основу малого боевого флота странников. По своим размерам ракета похожа на ракету предыдущего типа, однако обладая большей взрывной мощностью способна наносить больше повреждений кораблям и постройкам противников.\n\nТип ракеты: 3\nВзрывная сила: 100'),
(9224, '<b>Ракета ураган</b>\n\nРакета разработанная странниками, обладает внушительной мощностью и при этом запускается с большинства кораблей класса Фрегат. Ракета была найдена в охотнике странников. При этом именно эта ракета стоит на вооружении Уничтожителей. Не смотря на большие габариты корабля он не может использовать тяжелые ракеты.\n\nТип ракеты: 6\nВзрывная сила: 400'),
(9225, '<b>Ракета шершень</b>\n\nНаиболее используемая ракета в кораблях среднего флота. Урон который способна нанести эта ракета позволяет уничтожит большую часть мелкого флота с первого выстрела. Наиболее распространенное применение ракеты это вооружение Фрегатов и Гиперперехватчиков.\n\nТип ракеты: 5\nВзрывная сила: 250'),
(9226, '<b>Ракета шмель</b>\n\nПосле того, как ученые научились генерировать одномоментный синтез водорода в малых объемах - появилась возможность построить ракету с огромной силой взрыва. Именно ракеты Шмель стоят на вооружении Линкоров, что позволяет им проявить себя в бою в качестве основной боевой единицы.\n\nТип ракеты: 7\nВзрывная сила: 1200'),
(9229, '<b>Торговец дельфинов</b>\n\nКорабль расы разумных дельфинов. Никто до сих пор не может понять эту расу. Они научились работать с нашими торговыми станциями, однако делают это очень своеобразно. Все корабли дельфинов на самом деле это один корабль но каждая частица этого корабля существует сразу в двух экземплярах во вселенной. Таким образом корабль приземляется сразу на две станции в один корабль загружается товар, а из другого моментально выгружается. После торговой операции корабли исчезают из реального пространства. Некоторые пираты не брезгуют и захватывают корабли дельфинов, однако это не поощряется конфедерацией. Корабли очень медлительны и не поддаются разборке. Ходят слухи, что если захватить два корабля одной серии, то можно будет их аннигилировать, однако на практике эти слухи не оправдались.'),
(9232, '<b>Ракетный крейсер</b>\n\nКрейсер был разработан как корабль поддержки для флота. Большой трюм при полной загрузке ракетами позволяет развернуться в бою. Устройство корабля позволяет запускать любой тип ракет. При этом суммарный урон приносимый кораблем очень велик. При определенных условиях один такой крейсер способен справиться с небольшим флотом уничтожителей.'),
(9233, 'Устройство имплантируется в кору головного мозга и позволяет получать данные о точном положении противника. Именно это позволяет выбрать наиболее статичную цель и произвести точный удар по противнику.\n\nВероятность попадания увеличивается на 10%25'),
(9234, 'Устройство позволяет видеть объекты удаленные на немыслимые расстояния. Пользователю достаточно сосредоточить свой взгляд на удаленном объекте и он начнет приближаться. Это позволяет значительно улучшить показатель попадания по цели.\n\nВероятность попадания увеличивается на 20%25'),
(9235, 'Воздействуя на психику увеличивает вероятность захвата. При равных условиях команда противника начинает испытывать панику и катапультируется с корабля в случае неминуемой гибели.\n\nВероятность захвата увеличивается на 20%25'),
(9236, 'Гипноз воздействует на подсознание врага, вызывая самые страшные фантазии у каждого члена экипажа. Уровень и количество подверженных ничем не ограничивается.\n\nВероятность захвата увеличивается на 50%25'),
(9237, 'Имплантант.\n\nУстройство позволяет видеть объекты удаленные на немыслимые расстояния. Пользователю достаточно сосредоточить свой взгляд на удаленном объекте и он начнет приближаться. Это позволяет значительно улучшить показатель попадания по цели.\n\nВероятность попадания увеличивается на 20%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9239, 'Имплантант.\n\nУстройство имплантируется в кору головного мозга и позволяет получать данные о точном положении противника. Именно это позволяет выбрать наиболее статичную цель и произвести точный удар по противнику.\n\nВероятность попадания увеличивается на 10%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9240, 'Имплантант.\n\nГипноз воздействует на подсознание врага, вызывая самые страшные фантазии у каждого члена экипажа. Уровень и количество подверженных ничем не ограничивается.\n\nВероятность захвата увеличивается на 50%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9241, 'Имплантант.\n\nВоздействуя на психику увеличивает вероятность захвата. При равных условиях команда противника начинает испытывать панику и катапультируется с корабля в случае неминуемой гибели.\n\nВероятность захвата увеличивается на 20%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9242, 'Электронный микроскоп позволяет разглядеть внутреннюю структуру любого вещества, что позволяет выбрать наиболее правильный способ изучения объекта еще до его разработки в лаборатории.\n\nВероятность получения макета или чертежа увеличивается на 24%25'),
(9243, 'Имплантант.\n\nЭлектронный микроскоп позволяет разглядеть внутреннюю структуру любого вещества, что позволяет выбрать наиболее правильный способ изучения объекта еще до его разработки в лаборатории.\n\nВероятность получения макета или чертежа увеличивается на 24%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9246, '<b>Мобильная космическая станция</b>\n\nПопытки увеличить грузоподъемность авианосца не привели к желаемому результату, корабль получался очень хрупким и медленным. Ученые конфедерации долго разрабатывали новый принцип конструкции. Так появился гибрид корабля и космической станции. Количество потребляемого топлива приводит в трепет, однако станция обладает одним непревзойденным качеством, она способна в себя вмещать огромное количество кораблей. При этом это могут быть авианосцы с которых идет заправка самой станции. Уровень щитов позволяет достаточно долгое время продержатся в бою. В качестве приятного дополнения на станцию был установлен радар повышенной мощности.'),
(9248, '<b>Док стыковки</b>\n\nДок представляет собой огромные ворота с магнитным захватом цели. Сила магнитного захвата не велика и не позволяет затягивать корабли против их воли. Док оборудован всеми известными средствами наведения, для удачной стыковки. Количество кораблей для стыковки не ограничено, однако док достаточно долго производит маневр стыковки и для беспрерывной работы устанавливают несколько доков.\n\nРазрабатывается из Палубы авианосца'),
(9250, '<b>Радар станции</b>\n\nУстройство позволяет сканировать пространство всеми доступными способами. Для большей скорости сканирования применяется гравитационный метод определения смещения масс. Из картины гравитационных волн исключаются все относительно статичные объекты, а так же известные планеты, спутники и метеориты. Оставшиеся объекты представляют собой как правило корабли. Картина, полученная с помощью радара, отображает все корабли, присутствующие в звездной системе. Для станции радар был доработан и усилен, уровень приема увеличился до 5\n\nДля работы радару необходимо находится на некотором удалении от больших масс, поэтому он не работает на планетах и орбитах планет.'),
(9251, 'Интегрируясь с нейронной сетью позволяет быстрее запоминать любую информацию. Имплантант очень увеличивает нагрузку на мозг, бывали случаи несовместимости с наркотиками и алкоголем. Желательно после установки имплантанта не использовать никакие наркотические вещества, особенно содержащие спирт.\n\nСкорость изучения навыков увеличивается на 20%25'),
(9252, 'Имплантант.\n\nИнтегрируясь с нейронной сетью позволяет быстрее запоминать любую информацию. Имплантант очень увеличивает нагрузку на мозг, бывали случаи несовместимости с наркотиками и алкоголем. Желательно после установки имплантанта не использовать никакие наркотические вещества, особенно содержащие спирт.\n\nСкорость изучения навыков увеличивается на 20%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9255, '<b>Автономная станция разведки</b>\n\nАСР является не чем иным как модернизированным шпионским спутником. Она позволяет следить за любой звездной системой. Еще до освоения космоса человечество занималось вопросами глобальной ПРО и удаленного наблюдения за интересующими участками вселенной. Пришло время достать и модернизировать технологии прошлого.'),
(9259, '<b>Автономная станция странников</b>\n\nАСРС является не чем иным как модернизированным шпионским спутником. Она позволяет следить за любой звездной системой. Еще до освоения космоса человечество занималось вопросами глобальной ПРО и удаленного наблюдения за интересующими участками вселенной. Пришло время достать и модернизировать технологии прошлого.\n\nВ отличии от АСР построена на технологиях странников.'),
(9262, '<b>Автономная лазерная станция</b>\n\nАЛС была разработана на основе лазерной защиты. И используется для усиления орбитальной обороны и охраны АРС.'),
(9265, '<b>Автономная плазменная станция</b>\n\nАПС была разработана на основе орудий уничтожителя. И используется для усиления орбитальной обороны и охраны АРС.');
INSERT INTO `enciclopedia` (`object_id`, `desc`) VALUES
(9267, '<b>Малый док стыковки</b>\n\nДок мало чем отличается от основного дока стыковки. Позволяя стыковать малые корабли к автономным станциям. В доке использован минимум материалов для сокращения его общей массы\n\nРазрабатывается из Дока стыковки'),
(9270, '<b>Мобильная станция странников</b>\n\nПолучив достаточно устройств странников ученые разработали самую универсальную конструкцию. В настоящий момент доступна только полная комплектация. Станция включает в себя модули разведки и прикрытия, а так же модуль для перехвата. За счет использования более технологичных устройств странников удалось увеличить трюм станции, что позволяет стыковать больше кораблей за один раз. Двигатели пришлось использовать стандартные, из-за этого потребление топлива осталось таким же большим. Станция используется как переносной пункт для дозаправки кораблей. Благодаря своей функциональности нередко используется пиратами, для ограничения нелегального использования конфедерация запретила копирование макета.'),
(9271, 'Самое сложное в расчете гиперперехода, это предугадать положение звезд и их взаимодействие в 5 мерных пространствах. Для этой задачи как правило используются бортовой компьютер, однако он не обладает интуицией. Что бы подключить интуицию к расчетам существует этот имплантант. В логический отдел мозга отправляется ситуация, в которой необходимо принять интуитивное решение. Владелец имплантанта даже не замечая этого принимает наиболее важные решения, на расчет которых понадобились бы столетия. Скорость перемещения любого корабля увеличивается, поскольку расчеты требуют намного меньше времени.\n\nСкорость перемещения в гиперпространстве увеличивается на 15%25'),
(9272, 'Странники использовали иной подход к гиперпространству. Осталось несколько устройств подобного рода. Имплантант позволяет представить всю нашу вселенную и виртуально осуществить любое перемещение. Это позволяет точно рассчитать все флюктуации в пространстве и изменив траекторию в самом начале прыжка позволяет не корректировать ее во время полета. Каким образом устройство получает или рассчитывает информацию, что бы поддерживать виртуальную копию в актуальном состоянии, пока ученым конфедерации не известно.\n\nСкорость перемещения в гиперпространстве увеличивается на 25%25'),
(9273, 'Имплантант.\n\nСамое сложное в расчете гиперперехода, это предугадать положение звезд и их взаимодействие в 5 мерных пространствах. Для этой задачи как правило используются бортовой компьютер, однако он не обладает интуицией. Что бы подключить интуицию к расчетам существует этот имплантант. В логический отдел мозга отправляется ситуация, в которой необходимо принять интуитивное решение. Владелец имплантанта даже не замечая этого принимает наиболее важные решения, на расчет которых понадобились бы столетия. Скорость перемещения любого корабля увеличивается, поскольку расчеты требуют намного меньше времени.\n\nСкорость перемещения в гиперпространстве увеличивается на 15%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9274, 'Имплантант.\n\nСтранники использовали иной подход к гиперпространству. Осталось несколько устройств подобного рода. Имплантант позволяет представить всю нашу вселенную и виртуально осуществить любое перемещение. Это позволяет точно рассчитать все флюктуации в пространстве и изменив траекторию в самом начале прыжка позволяет не корректировать ее во время полета. Каким образом устройство получает или рассчитывает информацию, что бы поддерживать виртуальную копию в актуальном состоянии, пока ученым конфедерации не известно.\n\nСкорость перемещения в гиперпространстве увеличивается на 25%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9277, '<b>Линкор странников</b>\n\nДо сих пор идут споры, является ли этот корабль линкором. Однако корпус и размеры корабля заставляют отнести его к классу кораблей среднего звена. Это один из самых защищенных кораблей странников. По силе выстрела он отстает от Штурмовика и Уничтожителя, однако его основное преимущество это скорострельность относительно большими зарядами. Именно этот корабль лежал в основе Линкор-М. Скорость Линкора в реальном пространстве сравнима со скоростью корвета, однако в гиперпространстве Линкор потребляет большое количество урана и медленно перемещается.\n'),
(9278, '<b>Автономная квантовая станция</b>\n\nАКС была разработана на основе квантового модуля. И используется для усиления орбитальной обороны и охраны АРС. Это второй корабль после Линкор-Т с похожим типом вооружения.'),
(9283, '<b>Квантовая мина</b>\n\nКорабль использует всю мощность реактора для генерации одной квантовой волны. Запредельная нагрузка на реактор приводит к самоуничтожению мины после выстрела. Квантовые мины долгое время были запрещены галактической конвенцией, так как не имели направленного рупора атаки и часто их жертвами становились гражданские суда. После интеграции модуля свой-чужой мины допустили к производству и использованию.'),
(9286, '<b>Плазменная мина</b>\n\nПредставляет собой узкоспециализированный корабль с минимальным набором устройств для выстрела. Количество выстрелов ограничено мощностью реактора. Для максимальной эффективности реактор работает на запредельной мощности, что приводит к его уничтожению. По своей сути это одноразовое устройство которое используется как космическая мина.'),
(9289, '<b>Штурмовик - модифицированный</b>\n\nИзначальное предназначение корабля - атака крупных кораблей. Эти корабли являются первой силой против боевого флота. Сила выстрела корабля значительно превышает все современные орудия. Однако у корабля есть всего 1 выстрел и в случае промаха корабль становится прочной, но легкой целью. Корабли используются только в флоте, так как отсутствие трюма не позволяет перемещаться самостоятельно. Корабль хорошо проявил себя при охране колоний.'),
(9292, '<b>Штурмовик - тяжелый</b>\n\nУчитывая не совсем удачный опыт штурмовика-М в этом корабле модифицировали силу орудий. Это позволяет использовать корабль для уничтожения крупных кораблей. Однако у корабля есть всего 1 выстрел и в случае промаха корабль становится прочной, но легкой целью. Корабли используются только в флоте, так как отсутствие трюма не позволяет перемещаться самостоятельно. Корабль хорошо проявил себя при орбитальной охране колоний.'),
(9297, '<b>Глюонная мина</b>\n\nЛюбой источник энергии можно превратить в бомбу или мину. Достаточно высвободить всю накопленную энергию разом. Именно так происходит в глюонной мине. По мере приближения врага реакторы выходят на полную мощность и на определенном расстоянии от корабля срабатывает глюонный дестабилизатор высвобождая всю возможную энергию. На мине установлено устройство прикрытия, что бы во время "разогрева" мину нельзя было обнаружить на радарах.'),
(9299, '<b>Глюонный дестабилизатор</b>\n\nВо время испытания глюонного реактора странников проводился эксперимент по управлению полем используя меньшую энергию, это позволило бы использовать глюонные реакторы на планетарных базах. Побочным эффектом стал модуль который дестабилизирует глюоны и вызывает максимально быстрый выброс энергии. Все сведения об этом эксперименте до сих пор засекречены, однако учитывая необходимость в сильном вооружении дестабилизаторы продаются на рынке под строгим контролем со стороны конфедерации.'),
(9300, 'Во время обнаружения цели на радаре долгое время не было возможности анализировать сигнал в радиодиапазоне. Нейроимплантант посылает все принятые сигналы в аналитическую часть мозга, это позволяет распознать корабли не подающие сигналов. Такие корабли называются брошенными. Количество брошенных кораблей легко определяется, однако их точное местоположение остается загадкой.\n\nПоказывает количество потерянных кораблей в системе.\nСкорость перемещения в пространстве увеличивается на 10%25'),
(9301, 'Имплантант.\n\nВо время обнаружения цели на радаре долгое время не было возможности анализировать сигнал в радиодиапазоне. Нейроимплантант посылает все принятые сигналы в аналитическую часть мозга, это позволяет распознать корабли не подающие сигналов. Такие корабли называются брошенными. Количество брошенных кораблей легко определяется, однако их точное местоположение остается загадкой.\n\nПоказывает количество потерянных кораблей в системе.\nСкорость перемещения в пространстве увеличивается на 10%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9304, 'После изобретения имплантанта "нейропорт-2" ученые одной пиратской колонии начали разработку третей версии нейропорта. Эксперименты показали, что устройство опасно для использования. Иногда человек с установленными нейропортами не выходит из состояния обучения и остается с раздвоением личности на всегда. Будьте осторожны используя данный имплантант. Случаи неправильной работы единичны, однако большинство пилотов не сознается в использовании этих имплантантов.\n\nПозволяет изучать еще один навык параллельно\nСкорость изучения навыков увеличивается на 5%25'),
(9305, 'Имплантант.\n\nПосле изобретения имплантанта "нейропорт-2" ученые одной пиратской колонии начали разработку третей версии нейропорта. Эксперименты показали, что устройство опасно для использования. Иногда человек с установленными нейропортами не выходит из состояния обучения и остается с раздвоением личности на всегда. Будьте осторожны используя данный имплантант. Случаи неправильной работы единичны, однако большинство пилотов не сознается в использовании этих имплантантов.\n\nПозволяет изучать еще один навык параллельно\nСкорость изучения навыков увеличивается на 5%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9307, '<b>Автономный щит</b>\n\nУстройство разрабатывалось изначально для орбитальной обороны. Но из-за малой энергии защиты был снят с производства. Однако очень пригодился в период массовой постройки автономных станций. '),
(9308, 'Улучшая характеристики кораблей военные столкнулись с проблемой управления кораблями. Человек не может отдавать приказ сразу нескольким кораблям. Рации и аналитические системы помогают с этим, однако прорыв в области управления наступил с изобретением модуля объединения. Модуль позволяет группировать флота и корабли в любом количестве и в любом порядке. При правильном подходе управлять флотами любого размера становится приемлемо.\n\nПозволяет управлять группами флотов и кораблей.\nСкорость перемещения в гиперпространстве увеличивается на 10%25'),
(9309, 'Имплантант.\n\nУлучшая характеристики кораблей военные столкнулись с проблемой управления кораблями. Человек не может отдавать приказ сразу нескольким кораблям. Рации и аналитические системы помогают с этим, однако прорыв в области управления наступил с изобретением модуля объединения. Модуль позволяет группировать флота и корабли в любом количестве и в любом порядке. При правильном подходе управлять флотами любого размера становится приемлемо.\n\nПозволяет управлять группами флотов и кораблей.\nСкорость перемещения в гиперпространстве увеличивается на 10%25\n\nЧто бы установить имплантант, необходимо что бы он находился в одной точке с вашим персонажем. На одной станции, на одной планете или в одном корабле. После этого через меню обучение станет доступна установка имплантанта.\n\nУстанавливать можно только 1 такой имплантант.\n\n<font color="#FF0000">При смерти персонажа капсула восстанавливает новое тело без имплантантов.</font>'),
(9312, '<b>Корабль шпион</b>\n\nПосле появления первых пиратских баз, конфедерация начала разработку этого корабля. Основная задача корабля с шпионским модулем проникнуть в тыл противника и передать всю доступную информацию. Наполнение складов, количество построек, силу вооружения. Шпионский модуль позволяет полностью скрыть корабль со всех средств обнаружения, однако используемая для этого технология темпорального поля не позволяет передать или забрать материальные объекты. Все, что способен сделать корабль это переместить себя в заданную точку пространства и проявившись в настоящем времени передать полученную информацию. После этого корабль уходит в бесконечно далекое будущее.'),
(9314, '<b>Шпионский модуль</b>\n\nВо время исследования некоторые свойств пространства-времени был обнаружен интересный эффект, при замене одного измерения другим, есть возможность поместить объект в некое темпоральное поле, что позволяет перемещаться в обычном пространстве абсолютно незамеченным. После нескольких экспериментов удалось добится стабильного прибывания объекта в темпоральном поле, однако при униятожении поля объект лишь на короткое время оказывался в настоящем времени, а затем уходил в далекое будущее, что приводило к уничтожению всех образцов. Модуль и корабль на котором он установлен являются по своей сути одноразовыми.'),
(9313, '<b>Шпионский модуль</b>\n\nВо время исследования некоторые свойств пространства-времени был обнаружен интересный эффект, при замене одного измерения другим, есть возможность поместить объект в некое темпоральное поле, что позволяет перемещаться в обычном пространстве абсолютно незамеченным. После нескольких экспериментов удалось добится стабильного прибывания объекта в темпоральном поле, однако при униятожении поля объект лишь на короткое время оказывался в настоящем времени, а затем уходил в далекое будущее, что приводило к уничтожению всех образцов. Модуль и корабль на котором он установлен являются по своей сути одноразовыми.'),
(9323, '<b>Гипер врата</b>\n\nКорабль представляет собой 16 конечную звезду неимоверных размеров. В свернутом состоянии звезда не умещается даже в авианосце, от чего корабль приходится собирать на орбите. В действующем состоянии каждый луч звезды содержит на конце модуль гиперперехвата, а в центре звезды разполагается модуль гиперсинхронизации. Модули обеспечивают накачку энергии во врата в течении нескольких часов, после чего одним импульсом открывается гипертуннель, способный вместить целую планету. Вход и выход врат располагаются у разных планет и позволяют как бы менять их местами.\n\nВсе корабли, находящиеся на планете и орбите планеты остаются нетронутыми. Постройки и жители планеты смогут заметить изменения только по изменившемуся звездному небу над головой.\n\nВо время работы корабль не может находится в составе флота, не может перемещаться и нуждается в постоянной охране.'),
(9325, '<b>Модуль гиперсинхронизации</b>\n\nПосле создания модуля гиперперехвата военные начали требовать от ученых увеличение мощности перехвата, поскольку часть кораблей по прежнему перехватывалась трититами. Увеличивая количество перехватчиков никак не сказывалось на вероятности перехвата корабля трититом. Однако при точной синхронизации гравитационных волн удалось достичь кратковременный всплеск искажения в пространстве, побочным эффектом этого эксперимента оказался небольшой туннель в гиперпространстве.\n\nЭксперименты в космосе показали, что существует возможность построить гипер-туннель, этого можно добиться при точной когерентности гравитационных волн в двух разных точках вселенной. Для создания полностью идентичной волновой картины используется этот модуль, он способен передавать полную копию волны за нулевой отрезок времени на любое расстояние.\n\nПервое упоминание о таком устройстве встречается в бортовом журнале нескольких кораблей странников. Так приземлившись на планету корабль взлетел уже в другой звездной системе.\n\nПоскольку неизвестно всех отрицательных моментов использования данного устройства, и модуль и корабль собирающийся на его основе находятся под строгим контролем конфедерации.'),
(9328, '<b>Корвет корсаров</b>\n\nКорвет представляет собой среднее звено военной техники. Объединенные во флот корабли способны поражать цели в любой точки галактики. Не редко данный тип кораблей используют для захвата планет. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах.\n\nВ отличии от простого корвета корабль не посылает опознавательные данные, что позволяет ему атаковать не выдавая владельца. По сути это наемники.'),
(9331, '<b>Линкор корсаров</b>\n\nЛинкор относится к среднему звену военных кораблей. Это сильно защищенный корабль, обладающий большой мощью, что позволяет уничтожать врага еще до того, как он произведет выстрел. Линкор хорошо справляется как с малыми, так и с большими целями, однако не способен самостоятельно нападать на планеты. Грузовой отсек корабля не предназначен для транспортировки большого количества грузов, однако способен перевозить чертежи и макеты в неограниченных количествах. Скорость Линкора в реальном пространстве сравнима со скоростью корвета, однако в гиперпространстве Линкор потребляет большое количество урана и медленно перемещается.\n\nВ отличии от простого линкора корабль не посылает опознавательные данные, что позволяет ему атаковать не выдавая владельца. По сути это наемники.'),
(9334, '<b>Штурмовик корсаров</b>\n\nИзначальное предназначение корабля - атака крупных кораблей. Эти корабли являются первой силой против боевого флота. Сила выстрела корабля значительно превышает все современные орудия. Однако у корабля есть всего 1 выстрел и в случае промаха корабль становится прочной, но легкой целью. Корабли используются только в флоте, так как отсутствие трюма не позволяет перемещаться самостоятельно. Корабль хорошо проявил себя при охране колоний.\n\nВ отличии от простого штурмовика-М корабль не посылает опознавательные данные, что позволяет ему атаковать не выдавая владельца. По сути это наемники.');
