INSERT INTO `bot_out` (`id`, `text`) VALUES
(1, 'что бы заправить корабль - необходимо зайти в склад, выбрать корабль для заправки и переместить в него водород (или уран, смотря что надо)'),
(2, 'Возможно вы забыли переключить раскладку : )'),
(3, 'и тебе пока!'),
(4, 'привет!'),
(5, 'Чтобы найти потерянный корабль, необходим разведчик или другой корабль с радаром и какое нибудь вооружение. Перелетая от звезды к звезде обращайте внимание на желтые точки на карте системы, это чужие корабли, подлетите к ним. Если его имя Abandon - вы можете присвоить его себе.'),
(6, 'И тебе доброе утро!'),
(7, 'Что бы распаковать упаковку с газом - достаточно переработать ее в нанодиспенсере. Сделать это можно только на поверхности планеты.'),
(8, 'Любой газ (кислород, водород, хлор, азот) можно упаковать на заводе. Для процесса упаковки вам необходим "Чертеж упаковки ..." - который можно приобрести у конфедерации (торговля - конфедерация)'),
(9, 'Что бы построить что-то на планете, необходимо перейти в "местность", найти свободную клетку и перейти слева в закладку с шестеренкой. Там выбрать тип постройки и если вам хватает ресурсов - можете запустить постройку.'),
(10, 'Ответ 42'),
(11, 'Всегда рад помочь'),
(12, 'Если вы улетели от своей звезды и не можете вернутся, вам необходимо найти (купить) истребитель и заправить (можно купить) его ураном. Подлетев к своему кораблю объедините их в флот. После этого флотом можете вернутся домой.'),
(13, 'Если вы пытаетесь узнать откуда эта сумма и как ее получить - не стоит этого делать... Никак нельзя получить сумму с добропорядочного гражданина.'),
(14, 'Я на всякий случай лог сохранил, передам sharque : )');
