INSERT INTO `info_page` (`id`, `type`, `title`, `data`) VALUES
(1, 1, 'Новый корабль', 'В галактике найден новый корабль:<br>\r\nОхотник странников.<br>\r\nВ отличии от большинства кораблей корабль обладает как внушительной мощностью, так и радаром. В настоящий момент доступен и сам корабль и его макет.'),
(2, 1, 'Новый корабль', 'В галактике найден новый корабль:<br>\r\nАвианосец странников.<br>\r\nКорабль, обладая огромной грузоподъемностью снабжен уникальным набором двигателей и способен приземляться на поверхность планеты.'),
(3, 1, 'Изменения интерфейса.', 'Незначительно изменен интерфейс игры, продолжается общая стилизация игры. В настоящий момент изменены все управляющие элементы. Переработана вкладка купли и продажи на станции.'),
(4, 1, 'Новые задания', 'Добавлены новые Задания. Теперь даже опытному игроку не всегда под силу выполнить задание с первого раза. Пираты оккупируют планеты, и требуется ваша помощь в борьбе с ними.'),
(6, 1, 'Изменения интерфейса', 'Изменен интерфейс закладки "склад". Верхняя часть теперь отвечает полностью за корабль, нижняя часть относится к доступным местам для перемещения. Работать со складом теперь будет проще.\r\nВедутся работы над интерфейсом торговли.'),
(7, 1, 'Взрыв звезд.', 'Для оптимизации работы сервера теперь удаляются старые пользователи.\r\nЕсли игрок:\r\n- не прошел стадию обучения\r\n- не появлялся в игре 2 месяца\r\n- в его системе не наблюдается активность других игроков (нет чужих построек)\r\nВ системе происходит взрыв сверхновой, соответственно все планеты и звезда уничтожается.'),
(8, 1, 'Изменения интерфейса', 'Изменен интерфейс управления плеером, закладка конфедерация перенесена в интерфейс торговли. Полностью переработаны интерфейсы управления кораблями и станцией.'),
(9, 1, 'Вознаграждение за пиратов', 'Изменен метод подсчета премии за уничтожение пиратов. Теперь премия вычисляется из уничтоженного имущества, чтобы не провоцировать договорные войны. Полная сумма выплачивается в случае, если пират лично присутствовал на уничтоженном корабле.'),
(10, 1, 'Прием платежей', 'Мы принимаем платежи более 70 платежных систем. Теперь вы можете приобрести конфедераты любым удобным для вас способом.'),
(11, 1, 'Социальная реклама', 'Появилась группа на сайте Вконтакте, кнопку можно найти на главной странице.\r\nНапоминаем, что любые <b>легальные</b> рекламные действия (спам и мультоводство к этому не относится) будут поощряться.<br>\r\nЗа публикации обзоров игры на форумах и т.п. мы будем <b>платить конфедератами</b>!'),
(12, 1, 'Изменения интерфейса', 'Закончился переход на новый движок. Теперь все игровые модули построены на новом движке. Это экономит ресурсы компьютера и немного ускоряет прорисовку. Так же упростился процесс улучшения и запуска построек.'),
(13, 1, 'Изменения в обсчете боев', 'Теперь корабль находящийся в обороне сам нападает на приближающиеся корабли, однако его действия не портят репутацию владельца.\r\nПремия за голову пирата выплачивается только раз в сутки.'),
(16, 1, 'Переезд', 'Сервер полностью переехал на новый хостинг. Время отклика значительно сократилось, максимальное количество игроков увеличилось. Все ошибки связанные с переездом были устранены.<br><br>Добро пожаловать в игру!'),
(17, 1, 'Новый корабль', 'Корабль способен скрыть свое пребывание в системе. При объединении такого корабля в флот весь флот становится невидим для радара. Чем больше таких кораблей в флоте, тем больше вероятность стать невидимым. Если в системе есть 1 радарный корабль, то достаточно 1 корабля прикрытия в флоте. При наличии 15 радарных кораблей в системе - необходимо минимум 15 кораблей прикрытия в составе одного флота.'),
(18, 1, 'Рефералы', 'Готов механизм рефералов. Теперь, если игрок пришел по вашей ссылке вы получите 1 конфедерат как только он закончит обучение. А так же вы будете получать 10% от всех переводов в игру. Ссылку можно получить в игре в меню "Персонаж"'),
(19, 1, 'Новый корабль', 'Разведчик странников - обладает уникальным радаром, коэффициент усилителя 10, то есть он способен разглядеть флот с 9-ю кораблями прикрытия. При этом все остальные свойства совпадают с обычным разведчиком.'),
(20, 1, 'Новый корабль', 'Невидимка странников - Долгое время корабли не поддавались находке. В одной случайной экспедиции удалось обнаружить такой корабль визуально, после осмотра корабля он был доставлен на базу конфедерации, где был полностью демонтирован. Коэффициент искажения у корабля равен 10.'),
(21, 1, 'Новый корабль', 'Штурмовик странников - Корабль долгое время не удавалось захватить, поскольку корабль, как правило, находился в активной защите и уничтожал всех, кто пытался приблизится. Корабль удалось взять на абордаж используя бесчисленное скопление мелких кораблей трититов. Пока Трититы отвлекали основные силы противника, корабль взяла под свой контроль абордажная команда. В настоящий момент корабль доступен для покупки, однако заполучить макет корабля почти невозможно.'),
(22, 1, 'Новая система друг-враг', 'В игре введена система друзей и врагов.\r\nДля начала общие правила - если на вас напали, нападающий автоматически становится врагом.<br>\r\nПоменять отношение к человеку можно зайдя в панель информации о нем (знак вопроса правее ника в чате)\r\nДля удобства рядом со знаком вопроса стоит отметка об отношении (враг - красная, друг - зеленая)'),
(23, 1, 'Новое вооружение - ракеты.', 'Теперь даже относительно слабый корабль может нести в себе существенное вооружение. Количество ракет ограничено только размером трюма, однако не любая ракета подходит любому кораблю.'),
(24, 1, 'Переименование планет', 'Теперь есть возможность переименовывать свои планеты, а так же звезды, которые вам принадлежат. При захвате чужой колонии вы можете переименовать и ее.'),
(25, 1, 'Раса разумных дельфинов', 'В галактике появилась раса разумных дельфинов. Никто не знает откуда они появились, они не вступают в конфликты, не обращают внимание на статус или боевые заслуги. Все, что их интересует это прибыль. Если вы продаете что-то дешевле чем кто-то покупает, будьте уверены рано или поздно к вам прилетят дельфины. Они летают на очень медленных кораблях, однако всегда производят моментальную куплю-продажу.'),
(26, 1, 'Открыта энциклопедия', 'Теперь есть доступ в энциклопедию с главной страницы. Достаточно зайти в раздел FAQ и можно прочитать любую статью из энциклопедии.'),
(27, 1, 'Внутренняя почта', 'Теперь есть возможность отправлять сообщения пользователям в оффлайн. Когда игрок зайдет в игру - он получит сообщение.'),
(28, 1, 'Новый корабль', 'Крейсер был разработан как корабль поддержки для флота. Большой трюм при полной загрузке ракетами позволяет развернуться в бою. Устройство корабля позволяет запускать любой тип ракет. При этом суммарный урон приносимый кораблем очень велик. При определенных условиях один такой крейсер способен справиться с небольшим флотом уничтожителей.'),
(29, 1, 'Активизация пиратов', 'В галактике активизировались пираты и нападают на колонии. В настоящий момент со всех сторон приходят сводки о нападении пиратов на мирные колонии. Будьте бдительны и не оставляйте свои колонии без присмотра!'),
(30, 1, 'Термоядерный преобразователь', 'Появилась новая орбитальная постройка. С помощью преобразователя можно превращать одно вещество в другое. Это поможет справится с залежами лишних веществ, а так же добывать редкие материалы.'),
(31, 1, 'Визуализация боя', 'Появилась первая версия визуализации боев. Со временем обязательно будет дорабатываться, но уже сейчас можно посмотреть, что творится на боле боя.'),
(32, 1, 'Имплантанты', 'Появились имплантанты, установка которых позволяет моментально улучшить определенные навыки. Однако учтите, что смерть приведет к их потере.<br>\r\nПрицел ориона<br>\r\nАноптикон странников<br>\r\nГенератор паники<br>\r\nГипноз странников'),
(33, 1, 'Новый имплантант', 'Электронный микроскоп. Позволяет разглядеть внутреннюю структуру любого вещества, что позволяет выбрать наиболее правильный способ изучения объекта еще до его разработки в лаборатории. Вероятность получения макета или чертежа увеличивается на 24%'),
(34, 1, 'Новый корабль', 'Новый корабль - мобильная космическая станция. Единственный корабль, к которому можно пристыковаться. Можно обмениваться любым товаром между Станцией и кораблями внутри нее. Так же можно перемещать груз с корабля на корабль внутри станции.'),
(35, 1, 'Покупка корабля', 'Стала доступна покупка корабля без авианосца. Теперь после покупки корабль становится доступен в расконсервированном виде.'),
(36, 1, 'Премия за голову', 'Теперь есть возможность самостоятельно вкладывать деньги в смерть противника. Вы можете назначить любую премию за любого игрока. Премию получит тот, кто уничтожит его. Премии от разных игроков складываются. Ограничений по сумме нет.'),
(37, 1, 'Задания', 'Теперь после отказа от задания, конфедерация разрешает взять другое только через 5 минут.'),
(38, 1, 'Черные дыры', 'В галактике начали протекать странные процессы. Происходит Коллапс звезд и они превращаются в черную дыру. Конфедерация ведет исследование этого процесса, однако пока мало что известно о новых объектах.'),
(39, 1, 'Новый расчет премий', 'Теперь премия которая назначена за игрока другим игроком будет раздаваться каждому, кто уничтожил какую-либо собственность. Сумма выдаваемая за каждую уничтоженную единицу в 4 раза больше той, что платит конфедерация за собственность пирата.'),
(40, 1, 'Новый тип кораблей', 'Еще до освоения космоса человечество занималось вопросами глобальной ПРО и удаленного наблюдения за интересующими участками вселенной. Пришло время достать и модернизировать технологии прошлого. Автономная лазерная станция, автономная плазменная станция, автономная станция разведки, автономная станция странников. Станции позволяют стыковку и могут использоваться как перевалочная база.'),
(41, 1, 'Новая станция', 'Получив достаточно устройств странников ученые разработали самую универсальную конструкцию. В настоящий момент доступна только полная комплектация. Станция включает в себя модули разведки и прикрытия, а так же модуль для перехвата.'),
(42, 1, 'Новое задание', 'Конфедерация устремила свои корабли разведки в отдаленные части галактики. Однако роботы не способны в полной мере оценить находку. Вам предоставляется шанс исследовать эти точки. С чем вам придется столкнутся неизвестно никому. Это могут быть брошенные корабли или армада разъяренных пиратов.'),
(43, 1, 'Новые имплантанты', 'Стали доступны 2 новых имплантанта. Предиктор и Виртуализатор - оба устройства увеличивают скорость перемещения в гиперпространстве.'),
(44, 1, 'Изменена логика охраны объектов', 'Теперь при выставленном уровне защиты, пилот способный прилететь на орбиту или поверхность колонии не сможет снести постройку или поменять уровень защиты. Таким образом можно привлекать других игроков к постройке колонии не боясь потерять колонию.'),
(45, 1, 'Обновление чата', 'В чате добавлены закладки, теперь системные и приватные сообщения выводятся отдельно от общего канала.'),
(46, 1, 'Страховка конфедерации', 'Конфедерация предлагает застраховать невосполнимую собственность. Страховка действует до момента смерти. В случае вашей смерти вам вернут все имплантанты, однако страховка будет аннулирована. Не забывайте вовремя оформить страховку и вы никогда не потеряете имплантанты. Есть возможность купить несколько страховок "на перед", однако не забывайте следить за состоянием страховок.'),
(47, 1, 'Ракетная защита', 'Ученые конфедерации смогли добиться запуска ракет космос-космос с поверхности планет. Теперь ракетная защита может использовать ракеты, лежащие на складе планеты, для атаки.\r\nМаксимальный тип используемых ракет = уровень постройки - 1'),
(63, 1, 'Конфедераты!', '<a href="http://2pay.ru/oplata/xsollaoffers/?pay_inst=224&id=4032"><img src="/images/xsolla.png" align=left></a>\r\nЕсли вам нужны конфедераты, вы можете получить их выполняя офферы. Для этого достаточно перейти на сайт <a href="http://2pay.ru/oplata/xsollaoffers/?pay_inst=224&id=4032">xsolla</a> и следовать инструкциям. За выполнение "заданий" вы получите конфедераты. Все задания распределяются с использованием геотаргетинга, поэтому вы увидите только те предложения, которые доступны вашему региону.'),
(49, 1, 'Карта галактики', 'На карте теперь отображаются ваши друзья и враги. При полете во вражескую систему стоит особенно тщательно относится к сообщениям о гиперперехвате.'),
(50, 1, 'Стратегия', 'Ввиду сложной военной обстановки командование конфедерации изменило стратегию атаки. Корабли Линкор-Т и схожие с ними теперь производят первый выстрел, это позволит уничтожать мелкие корабли противника не тратя на них драгоценные ракеты.'),
(51, 1, 'Закладка отношения', 'Теперь можно отслеживать ваши дипломатические отношения в любое время в не зависимости от того в сети ваш враг или нет. А так же можно узнать всех, кто считает вас врагом или другом.'),
(53, 1, 'Орбитальный склад', 'Увеличен объем хранимого имущества на орбите. Каждое улучшение орбитального склада увеличивает его объем на 15000.'),
(54, 1, 'Стратегия и тактика', 'Стратегия и тактика приведены к математическому соответствию.\r\n\r\nТактика - чем выше ваш уровень тактика, тем более мощный корабль будет стрелять первым.\r\nСтратегия - чем выше уровень стратега, тем более подходящий корабль будет выбираться для атаки.'),
(55, 1, 'Новые корабли', 'Введены 2 новых типа корабля.\r\n\r\nЛинкор странников\r\nАвтономная квантовая станция'),
(56, 1, 'Космические мины', 'Появились 2 новые мины. Квантовая мина - поражает все корабли противника, плазменная мина - наносит 4 выстрела по 350. Мины по своей сути одноразовые корабли которые уничтожаются при подрыве.'),
(57, 1, 'Астероиды', 'В системах где давно никто не живет произошли изменения. Бывшие родные планеты частично взорвались. С целью обеспечения безопасности торговых станций конфедерация покинула эти планеты. Они доступны для заселения.'),
(58, 1, 'Навыки', 'Появились новые знания. Теперь можно усилить обороноспособность планеты изучением наук. Новые навыки: защита планет, плазменная оборона, лазерная оборона, квантовая оборона, мазерная оборона.'),
(60, 1, 'Изменена логика захвата колонии.', 'После захвата колонию можно ограбить, однако что бы снести постройки или установить свой уровень защиты необходимо минимум 3 дня. В это время защиту придется удерживать флотом. По прошествии трех дней последние повстанцы покидают планету и ей можно пользоваться новым хозяевам.'),
(61, 1, 'Новый корабль', 'Штурмовик модифицированный. Изначальное предназначение корабля - атака крупных кораблей. Эти корабли являются первой силой против боевого флота. Сила выстрела корабля значительно превышает все современные орудия. Однако у корабля есть всего 1 выстрел и в случае промаха корабль становится прочной, но легкой целью. Корабли используются только в флоте, так как отсутствие трюма не позволяет перемещаться самостоятельно. Корабль хорошо проявил себя при охране колоний.'),
(62, 1, 'Пленных не брать!', 'Появился новый приказ для кораблей. Теперь можно отключить абордаж и все встреченные корабли будут уничтожатся на месте без захвата.'),
(64, 1, 'Улучшение производства', 'Теперь заводы, сборочные цеха и термоядерные преобразователи запоминают последнее задания и по возможности стараются его повторить.'),
(65, 1, 'Дополнение', 'Теперь при постройки сооружений, запоминается последнее построенное здание и дальше можно строить те же постройки. Стало удобней строить несколько построек подряд. Так же запоминается последний корабль, это пригодится при дальних походах.'),
(66, 1, 'Новые корабли', 'Пересчитаны и сбалансированы все корабли. Скорости кораблей стали более равномерные, защита осталась на прежнем уровне. Сильно изменилось потребление топлива и составы кораблей.'),
(67, 1, 'Потерянные корабли', 'Теперь, в случае когда корабль сбивается с курса и оказывается в неизвестной точке - он подает сигнал СОС. Силы конфедерации самостоятельно сопровождают его до родной планеты. Это должно решить проблему с зависшими кораблями.'),
(68, 1, 'Вынужденное обновление системы', 'Сегодня 17.08.2011 в течении дня были проблемы с сервером. Приносим свои изменения, были вынуждены произвести обновление системы из-за серьезной уязвимости в системе безопасности.'),
(69, 1, 'Удаленные заводы', 'Теперь корабли КУУ получили возможность запускать все заводы одним разом на колониях. Запускается максимально возможное количество циклов. Запускаются только те заводы на которых что-то уже производилось.'),
(70, 1, 'Упрощение процесса производства.', 'Заводы, сборочные цеха и другие сооружения по производству теперь запоминают количество циклов во время запуска. Таким образом больше не надо каждый раз выставлять одно и то же количество циклов.'),
(71, 1, 'Апгрейд', 'В связи с недостатком ресурсов на сервере 7-го сентября будет производится апгрейд системы. Сервер будет временно недоступен.'),
(72, 1, 'Мины на складе', 'В закладке "склад" больше не отображаются длинные списки мин, что бы не мешать искать нужные корабль под загрузку.'),
(73, 1, 'Новое вооружение', 'Увеличена сила мин. Квантовая мина до 120, Плазменная мина до 125*9. Так же появилась новая мина - Глюонная мина, мощностью 20*600.'),
(74, 1, 'Новый навык', 'Физик ядерщик. Ускоряет процесс переработки материалов на термоядерном преобразователе каждый уровень дает 4% ускорения. Требует больших знаний в геологии.'),
(75, 1, 'Увеличен склад', 'Теперь склад планеты вмещает 250000 единиц товара, что в 5 раз больше прежнего.'),
(76, 1, 'Удаленный запуск нанодиспенсеров', 'Теперь при переработке материалов в информационных сообщениях указывается имя планеты на которой запущена переработка.'),
(77, 1, 'Новый интерфейс кораблей', 'Изменен интерфейс кораблей, теперь есть возможность отфильтровать корабли и сократить список. Приказы собраны в один элемент, что позволило увеличить количество выводимых кораблей.'),
(78, 1, 'Новый имплантант', '"Импульсный анализатор" - помогает искать потерянные корабли, побочный эффект - ускоряет корабли.'),
(79, 1, 'Новый имплантант нейропорт-2', 'По своей сути представляет дополнительный порт для подключения обучающих устройств. Имплантант удалось изготовить после того, как нейрохирурги нашли возможность изменять потоки сигналов в головном мозге. По сути этот имплантант это искусственное введение человека в состояние контролируемой шизофрении с раздвоением личности. После обучения личности складываются. Отрицательных побочных эффектов не выявлено. Условно положительный побочный эффект это ускорение изучения навыков.\r\n\r\nСкорость изучения навыков увеличивается на 5%'),
(80, 1, 'Новый имплантант нейропорт-3', 'После изобретения имплантанта "нейропорт-2" ученые одной пиратской колонии начали разработку третей версии нейропорта. Эксперименты показали, что устройство опасно для использования. Иногда человек с установленными нейропортами не выходит из состояния обучения и остается с раздвоением личности на всегда. Будьте осторожны используя данный имплантант. Случаи неправильной работы единичны, однако большинство пилотов не сознается в использовании этих имплантантов.\r\n\r\nСкорость изучения навыков увеличивается на 5%'),
(81, 1, 'Новые возможности', 'Добавлена возможность запуска преобразователей из меню команд корабля удаленного управления.'),
(82, 1, 'Новый имплантант.', 'На рынке появился новый имплантант "Модуль объединения" который позволяет управлять группами флотов.'),
(83, 1, 'Пираты', 'Пираты стали немного злее, теперь в их распоряжении есть мины и автономные станции.'),
(84, 1, 'Пираты в галактике', 'По сообщениям со всех концов галактики пираты начали наступательные действия на просторах галактики. Они захватывают колонии и вымогают деньги! Конфедерация ведет активные поиски их гнезда, что бы нанести ответный удар!'),
(85, 1, 'Добавлены новые способы оплаты.', 'Теперь мы принимаем более 100 видов платежей.'),
(86, 1, 'Обновление интерфейса', 'Теперь можно посмотреть когда игрок был последний раз в эфире. Это поле добавленно в информации о всех игроках.'),
(87, 1, 'Обновлен интерфейс складов', 'Теперь можно выделять несколько кораблей и несколько вещей одновременно. Это позволяет снабдить целый флот ракетами за несколько действий.'),
(88, 1, 'Цены на корабли', 'Изменены цены на большинство кораблей. Макеты и чертежи остались по старым ценам.'),
(89, 1, 'Доработка внешнего вида', 'Энциклопедия частично иллюстрированна, теперь видно что из себя представляют все постройки, а так же минералы первого слоя. При переносе нескольких вещей в несколько кораблей теперь можно следить за прогрессом загрузки корабля.'),
(90, 1, 'Новый приказ', 'Теперь на удаленных колониях можно запускать сборочные цеха. Это позволяет переложить обязанности производства полностью на колонии.'),
(91, 1, 'Новое задание', 'Конфедерация начала активные поиски пиратов, нередко флот конфедерации и пиратов оказываются равны по силе. В этот момент конфедерация обращается к вам за помощью в битве.'),
(92, 1, 'Новый корабль шпион', 'Позволяет исследовать любую планету и получить подробный список вооружения, защиты, а так же частично список складов и флотов на орбите и планете. Корабль не обнаруживается перехватчиками и орбитальной защитой.'),
(93, 1, 'Интерфейс покупки', 'Добавлена возможность указывать количество покупаемого товара.'),
(94, 1, 'Новая музыка', 'Добавлено 28 радиостанций, теперь звуковое сопровождение будет более разнообразно. В ближайшее время будет добавлено еще несколько.'),
(95, 1, 'Доработка интерфейса', 'Переделана карта звездной системы, теперь планеты и астероиды выглядят более реалистично, что несомненно помогает погрузится в мир космоса.'),
(96, 1, 'Новый корабль', 'Корабль "Гипер врата" - новое слово в технологии странников. Корабль способный менять местами планеты. Теперь можно собрать свои колонии в одной системе или раскидать колонии противника по всей галактике.'),
(97, 1, 'Новое знание', 'Астроинженер - позволяет сократить время перемещения планет.'),
(98, 1, 'Новая возможность', 'Теперь с корабля удаленного управления можно запускать орбитальный сборочный цех.'),
(99, 1, 'Изменение в интерфейсе', 'Изменен интерфейс модуля "корабли", теперь список приказов изначально не перекрывает список кораблей.'),
(100, 1, 'Новый фон в системе', 'Теперь в каждой системе разный задний план. Всего различных фонов 60, надеюсь разнообразие скрасит пребывание в холодном космосе.'),
(101, 1, 'Корабли корсаров', 'Появился новый тип кораблей. Их невозможно идентифицировать, во время атаки они не сообщают сведения о нападающем, что позволяет им практически безнаказанно атаковать корабли и колонии.'),
(102, 1, 'Продажа корсаров', 'Конфедерация официально продает корабли корсаров. Можно купить себе целый флот наемников.');
