-- sharque homeworld buildings (register/gensystem.page)
ON DUPLICATE KEY UPDATE `last_pos` = VALUES(`last_pos`);

SET @map_empty = REPEAT('0', 900);
SET @map_top = INSERT(@map_empty, 466, 1, '6');
SET @map_bld = INSERT(@map_empty, 466, 1, 'C');
SET @orbit_lin = INSERT(REPEAT('0', 50), 5, 1, 'T');
ON DUPLICATE KEY UPDATE `top`=VALUES(`top`), `mdl`=VALUES(`mdl`), `btm`=VALUES(`btm`), `fnd`=VALUES(`fnd`), `bld`=VALUES(`bld`);
ON DUPLICATE KEY UPDATE `lin` = VALUES(`lin`);
UPDATE `planets` SET `occuped` = 1 WHERE `id` = 21222;

-- titul zero (empty title)

-- tituls for premium title objects present in catalog
SELECT o.id, o.id, o.name
FROM objects o
WHERE o.class = 9 AND o.cprice > 0
ON DUPLICATE KEY UPDATE object_id = VALUES(object_id), name = VALUES(name);

-- market rows for tradeable resource objects (class 1)
SELECT o.id, 0, 0, o.myprice, 0, 0, 100
FROM objects o
WHERE o.class = 1
ON DUPLICATE KEY UPDATE avg_price = VALUES(avg_price);

-- architect title for sharque
  ON DUPLICATE KEY UPDATE `name` = 'Архитектор', `object_id` = 22;

UPDATE ship_types SET w_sum = w_power * IF(w_count = 0, 1, w_count);

UPDATE objects SET minprice = 0 WHERE minprice IS NULL;




UPDATE `users` SET `titul` = 22 WHERE `id` = 16 AND `login` = 'sharque';


UPDATE `users` SET `place_id` = 21222, `place_type` = 1, `err_login` = '0000-00-00 00:00:00', `password` = MD5('test'), `last_ip` = '127.0.0.1', `volume_music` = 0 WHERE `id` = 16;
UPDATE `users_active` SET `lastlogin` = '2026-07-20 00:00:00' WHERE `id` = 16;

